    fn caches_persist_enabled() -> bool {
        use std::sync::OnceLock;
        static EN: OnceLock<bool> = OnceLock::new();
        *EN.get_or_init(|| {
            !matches!(
                std::env::var("CV_CACHES_PERSIST").ok().as_deref(),
                Some("0") | Some("false") | Some("off")
            )
        })
    }
