    fn flush_cache(name: &str, entries: &Rc<RefCell<HashMap<String, cv_js::Value>>>) {
        if !caches_persist_enabled() {
            return;
        }
        let snapshot: Vec<(String, cv_js::Value)> = entries
            .borrow()
            .iter()
            .map(|(k, v)| (k.clone(), v.clone()))
            .collect();
        opfs::persist_cache(name, &snapshot);
    }
