                let callback = args.get(1).cloned().unwrap_or(cv_js::Value::Undefined);
                let request_fn = send_provider.borrow().get("request").cloned();
                let result = if let Some(request_fn) = request_fn {
                    interp.call_value(request_fn, vec![request])?
                } else {
                    cv_js::interp::make_settled_promise(true, cv_js::Value::Undefined)
                };
