                    nonce.copy_from_slice(&iv);
                    let result = if key.len() == 32 {
                        let mut k = [0u8; 32];
                        k.copy_from_slice(&key);
                        cv_crypto::aes_gcm::Aes256Gcm::open(&k, &nonce, &aad, &data)
                    } else {
                        let mut k = [0u8; 16];
                        k.copy_from_slice(&key);
                        cv_crypto::aes_gcm::Aes128Gcm::open(&k, &nonce, &aad, &data)
                    };
