        // resolve regardless of where self sits; they no-op if self isn't in the
        // rendered tree yet (a detached created subtree serializes on append).
        let self_nid = obj_for_outer_set
            .borrow()
            .get(NODE_ID_ATTR)
            .map(|v| v.to_display_string());
