            let mut p = pending_for_outer.borrow_mut();
            p.push(DomMutation::InsertBefore {
                parent_path: Vec::new(),
                before_index: 0,
                nodes: nodes.clone(),
                before_nid: Some(self_nid.clone()),
            });
            p.push(DomMutation::Remove {
                path: Vec::new(),
                nid: Some(self_nid),
            });
