    #[test]
    fn dom_content_loaded_late_init_calls_external_global() {
        // Reproduce mail.hyvechain.com's particle-init pattern: an external
        // (non-defer) script defines a global, then a later inline script
        // registers a DOMContentLoaded listener that calls a local init fn IF
        // the global exists. The particle background never started, so verify
        // the whole chain: external global defined → DCL fires → init runs.
        let unique = format!(
            "tb_dcl2_{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        );
        let dir = std::env::temp_dir().join(unique);
        std::fs::create_dir_all(&dir).unwrap();
        let script_path = dir.join("plib.js");
        let html_path = dir.join("index.html");
        std::fs::write(
            &script_path,
            "window.PLib = function(){ document.title += '|P'; };",
        )
        .unwrap();
        std::fs::write(
            &html_path,
            "<!doctype html><title>go</title>\
             <script src=\"plib.js\"></script>\
             <script>function startIt(){ if (typeof PLib === 'undefined') return; PLib(); }\
             document.addEventListener('DOMContentLoaded', function(){ if (typeof PLib !== 'undefined') startIt(); });</script>",
        )
        .unwrap();
        let html = std::fs::read_to_string(&html_path).unwrap();
        let label = format!("file:///{}", html_path.display());
        let cfg = cv_layout::LayoutConfig::default();
        let (runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(&html, &label, &cfg, "").expect("render ok");
        assert_eq!(
            runtime.title_override().as_deref(),
            Some("go|P"),
            "DCL listener should fire and call the external global"
        );
        let _ = std::fs::remove_file(&script_path);
        let _ = std::fs::remove_file(&html_path);
        let _ = std::fs::remove_dir(&dir);
    }

    #[test]
    fn window_lifecycle_listeners_fire() {
        // `window.addEventListener('load'|'DOMContentLoaded', …)` uses a separate
        // listener store from document; the page-load lifecycle must still fire
        // them (it's one of the most common init hooks on the web).
        let html = "<!doctype html><title>x</title><script>\
            window.addEventListener('load', function(){ document.title += '|wload'; });\
            window.addEventListener('DOMContentLoaded', function(){ document.title += '|wdcl'; });\
            </script>";
        let cfg = cv_layout::LayoutConfig::default();
        let (runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");
        let title = runtime.title_override().unwrap_or_default();
        assert!(
            title.contains("wload"),
            "window load should fire, got {title:?}"
        );
        assert!(
            title.contains("wdcl"),
            "window DOMContentLoaded should fire, got {title:?}"
        );
    }

