    #[test]
    fn flatten_inline_runs_preserves_per_segment_color() {
        // Hacker News title cell: a black `<a>` story link next to a gray
        // `(domain)`. Flattening must keep BOTH colors (was: one node, all the
        // container's gray — every title rendered gray instead of black).
        let black = cv_layout::Color {
            r: 0,
            g: 0,
            b: 0,
            a: 255,
        };
        let gray = cv_layout::Color {
            r: 130,
            g: 130,
            b: 130,
            a: 255,
        };
        let mut node = cv_layout::StyledNode {
            kind: cv_layout::StyledKind::Element {
                tag: "td".to_string(),
            },
            style: cv_layout::Style {
                text_color: Some(gray),
                ..Default::default()
            },
            children: vec![
                cv_layout::StyledNode {
                    kind: cv_layout::StyledKind::Element {
                        tag: "a".to_string(),
                    },
                    style: cv_layout::Style {
                        text_color: Some(black),
                        link_href: Some("/story".to_string()),
                        ..Default::default()
                    },
                    children: vec![cv_layout::StyledNode {
                        kind: cv_layout::StyledKind::Text("Title".to_string()),
                        style: cv_layout::Style {
                            text_color: Some(black),
                            ..Default::default()
                        },
                        children: Vec::new(),
                    }],
                },
                cv_layout::StyledNode {
                    kind: cv_layout::StyledKind::Text(" (domain)".to_string()),
                    style: cv_layout::Style {
                        text_color: Some(gray),
                        ..Default::default()
                    },
                    children: Vec::new(),
                },
            ],
        };
        flatten_inline_runs(&mut node);
        assert_eq!(
            node.children.len(),
            2,
            "expected 2 colored segments, got {}",
            node.children.len()
        );
        let c0 = node.children[0].style.text_color.unwrap();
        assert_eq!((c0.r, c0.g, c0.b), (0, 0, 0), "story title must stay black");
        assert_eq!(node.children[0].style.link_href.as_deref(), Some("/story"));
        let c1 = node.children[1].style.text_color.unwrap();
        assert_eq!(
            (c1.r, c1.g, c1.b),
            (130, 130, 130),
            "(domain) must stay gray"
        );
    }

