    fn test_renderer_broker(pid: u32) -> std::sync::Arc<cv_content::broker::Broker> {
        let broker = std::sync::Arc::new(cv_content::broker::Broker::new());
        broker.register(cv_content::broker::ChildRecord {
            kind: cv_content::broker::ChildKind::Renderer,
            pid,
            alive: true,
            origin: Some("https://example.com".into()),
            death_reason: None,
        });
        broker
    }

    #[test]
    fn browser_renderer_session_marks_bad_direction_as_bad_message() {
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        let broker = test_renderer_broker(77);
        let mut session = BrowserRendererSession::new(77, broker.clone(), browser_ep);

        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::LayoutRequest {
                    url: "https://example.com/".into(),
                    viewport_w: 800,
                    viewport_h: 600,
                    html: b"<p>bad</p>".to_vec(),
                },
            )
            .expect("send invalid renderer msg");

        let err = session
            .recv_event()
            .expect_err("direction must be rejected");
        assert!(
            err.contains("invalid renderer message direction")
                || err.contains("browser-only renderer IPC")
        );
        assert_eq!(
            broker.death_reason(77),
            Some(cv_content::broker::ChildDeathReason::BadMessage)
        );
    }

    #[test]
    fn browser_renderer_session_requires_handshake_before_paint() {
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        let broker = test_renderer_broker(88);
        let mut session = BrowserRendererSession::new(88, broker.clone(), browser_ep);

        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::PaintReady {
                    width: 1,
                    height: 1,
                    bitmap_bgra: vec![0, 0, 0, 255],
                },
            )
            .expect("send paint");

        let err = session
            .recv_event()
            .expect_err("paint before handshake must fail");
        assert!(err.contains("paint before handshake"));
        assert_eq!(
            broker.death_reason(88),
            Some(cv_content::broker::ChildDeathReason::BadMessage)
        );
    }

    #[test]
    fn browser_renderer_session_accepts_handshake_then_paint() {
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        let broker = test_renderer_broker(99);
        let mut session = BrowserRendererSession::new(99, broker.clone(), browser_ep);

        session.send_handshake(1).expect("send browser handshake");
        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::HandshakeAck {
                    renderer_version: 1,
                },
            )
            .expect("send handshake ack");
        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::PaintReady {
                    width: 1,
                    height: 1,
                    bitmap_bgra: vec![1, 2, 3, 4],
                },
            )
            .expect("send paint");

        assert_eq!(
            session.recv_event().expect("handshake recv"),
            Some(BrowserRendererEvent::HandshakeAck {
                renderer_version: 1
            })
        );
        assert_eq!(
            session.recv_event().expect("paint recv"),
            Some(BrowserRendererEvent::PaintReady {
                width: 1,
                height: 1,
                bitmap_bgra: vec![1, 2, 3, 4],
            })
        );
        assert_eq!(broker.death_reason(99), None);
    }

    #[test]
    fn browser_renderer_host_round_trips_browser_messages_over_message_pipe() {
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        let broker = test_renderer_broker(111);
        let mut host = BrowserRendererHost::new(
            111,
            broker.clone(),
            browser_ep,
            Some("https://example.com".into()),
        );

        host.send_handshake(1).expect("send handshake");
        host.request_layout(
            "https://example.com/".into(),
            320,
            200,
            b"<html><body>ok</body></html>".to_vec(),
        )
        .expect("send layout request");

        let (_id, first_msg): (u32, cv_ipc::Msg) = renderer_ep.try_recv().expect("recv handshake");
        assert_eq!(
            first_msg,
            cv_ipc::Msg::Handshake {
                protocol_version: 1
            }
        );
        let (_id, second_msg): (u32, cv_ipc::Msg) = renderer_ep.try_recv().expect("recv layout");
        assert_eq!(
            second_msg,
            cv_ipc::Msg::LayoutRequest {
                url: "https://example.com/".into(),
                viewport_w: 320,
                viewport_h: 200,
                html: b"<html><body>ok</body></html>".to_vec(),
            }
        );

        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::HandshakeAck {
                    renderer_version: 1,
                },
            )
            .expect("send handshake ack");
        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::PaintReady {
                    width: 1,
                    height: 1,
                    bitmap_bgra: vec![9, 8, 7, 6],
                },
            )
            .expect("send paint");

        assert_eq!(
            host.recv_event().expect("recv handshake ack"),
            Some(BrowserRendererEvent::HandshakeAck {
                renderer_version: 1
            })
        );
        assert_eq!(
            host.recv_event().expect("recv paint"),
            Some(BrowserRendererEvent::PaintReady {
                width: 1,
                height: 1,
                bitmap_bgra: vec![9, 8, 7, 6],
            })
        );
        assert_eq!(broker.death_reason(111), None);
    }

    // ---- A2: persistent IPC marshaling --------------------------------

    /// The browser session decodes a renderer `CommitFrame` (the persistent
    /// frame envelope) into a `CommitFrame` event carrying the raw payload +
    /// epoch — undecoded, so the stale-frame drop can act on `epoch` without
    /// paying the (large) frame decode.
    #[test]
    fn browser_session_surfaces_commit_frame_with_epoch_and_payload() {
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        let broker = test_renderer_broker(222);
        let mut session = BrowserRendererSession::new(222, broker.clone(), browser_ep);

        session.send_handshake(1).expect("handshake");
        renderer_ep
            .send(0, &cv_ipc::Msg::HandshakeAck { renderer_version: 1 })
            .expect("ack");
        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::CommitFrame {
                    epoch: 17,
                    payload: vec![10, 20, 30, 40],
                },
            )
            .expect("commit frame");

        assert_eq!(
            session.recv_event().expect("recv ack"),
            Some(BrowserRendererEvent::HandshakeAck { renderer_version: 1 })
        );
        assert_eq!(
            session.recv_event().expect("recv commit"),
            Some(BrowserRendererEvent::CommitFrame {
                epoch: 17,
                payload: vec![10, 20, 30, 40],
            })
        );
        assert_eq!(broker.death_reason(222), None);
    }

    /// A `CommitFrame` before the handshake completes is a protocol
    /// violation and must be rejected (the renderer cannot legitimately
    /// commit a frame before acking).
    #[test]
    fn browser_session_rejects_commit_frame_before_handshake() {
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        let broker = test_renderer_broker(223);
        let mut session = BrowserRendererSession::new(223, broker.clone(), browser_ep);
        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::CommitFrame {
                    epoch: 1,
                    payload: vec![0],
                },
            )
            .expect("send frame");
        let err = session
            .recv_event()
            .expect_err("frame before handshake must fail");
        assert!(err.contains("frame before handshake"));
        assert_eq!(
            broker.death_reason(223),
            Some(cv_content::broker::ChildDeathReason::BadMessage)
        );
    }

    /// End-to-end persistent marshaling WITHOUT a process: a renderer-side
    /// `cv_ui::PaintData` + tabs are encoded into a `Msg::CommitFrame`,
    /// pushed over an in-process `MessagePipe`, decoded by the browser-side
    /// session, then run back through `frame_codec::decode_frame` — proving
    /// the full ToPage/FromPage frame path the cross-process bridge uses is
    /// byte-faithful (this is the in-process analog of the spawn test).
    #[test]
    fn persistent_frame_marshals_end_to_end_over_message_pipe() {
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        let broker = test_renderer_broker(224);
        let mut session = BrowserRendererSession::new(224, broker.clone(), browser_ep);

        // Renderer side: build a representative frame and commit it.
        let mut bmp = cv_gfx::Bitmap::new(4, 3);
        for (i, px) in bmp.pixels.iter_mut().enumerate() {
            *px = 0xFF00_0000 | (i as u32 * 0x0001_0203);
        }
        let paint = cv_ui::PaintData {
            bitmap: std::sync::Arc::new(bmp),
            texts: vec![cv_ui::TextItem {
                x: 8,
                y: 4,
                w: 100,
                h: 24,
                font_size_px: 16,
                bold: false,
                font_weight: 0,
                italic: false,
                font_family: None,
                color_rgb: (1, 2, 3),
                color_alpha: 255,
                text: "https://example.com/".into(),
                align: cv_ui::TextAlign::Left,
                letter_spacing_px: 0,
                is_chrome: true,
                text_gradient: None,
            }],
            layout_root: None,
            hit_regions: vec![cv_ui::HitRegion {
                x: 0,
                y: 30,
                w: 50,
                h: 12,
                href: Some("/next".into()),
                element_path: Some(vec![0, 1]),
            }],
            title: "Example".into(),
            current_url: "https://example.com/".into(),
            chrome_h: 64,
            viewport_h: 800,
            caret_rect: None,
            caret_color: None,
            scrollbar_theme: cv_ui::ScrollbarTheme::default(),
            property_trees: None,
            retained: None,
            content_origin_y: 0,
            document_h: 0,
        };
        let tabs = vec![cv_ui::TabSummary {
            id: 0,
            title: "Example".into(),
            url: "https://example.com/".into(),
            active: true,
        }];
        let payload = frame_codec::encode_frame(&paint, &tabs);

        session.send_handshake(1).expect("handshake");
        renderer_ep
            .send(0, &cv_ipc::Msg::HandshakeAck { renderer_version: 1 })
            .expect("ack");
        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::CommitFrame {
                    epoch: 3,
                    payload: payload.clone(),
                },
            )
            .expect("commit");

        // Browser side: drain the ack, then the frame, then decode it.
        assert!(matches!(
            session.recv_event().expect("ack"),
            Some(BrowserRendererEvent::HandshakeAck { .. })
        ));
        let event = session.recv_event().expect("commit").expect("some");
        let (epoch, payload_back) = match event {
            BrowserRendererEvent::CommitFrame { epoch, payload } => (epoch, payload),
            other => panic!("expected CommitFrame, got {other:?}"),
        };
        assert_eq!(epoch, 3);
        let frame = frame_codec::decode_frame(&payload_back).expect("decode frame");
        assert_eq!(frame.paint.bitmap.width, 4);
        assert_eq!(frame.paint.bitmap.height, 3);
        assert_eq!(frame.paint.bitmap.pixels, paint.bitmap.pixels);
        assert_eq!(frame.paint.title, "Example");
        assert_eq!(frame.paint.current_url, "https://example.com/");
        assert_eq!(frame.paint.texts.len(), 1);
        assert_eq!(frame.paint.texts[0].text, "https://example.com/");
        assert_eq!(frame.paint.hit_regions.len(), 1);
        assert_eq!(frame.paint.hit_regions[0].href.as_deref(), Some("/next"));
        assert_eq!(frame.tabs.len(), 1);
        assert!(frame.tabs[0].active);
    }

    /// `ToPage` commands map 1:1 to the persistent browser→renderer `Msg`
    /// variants the bridge writer emits — the wire shapes the renderer
    /// process consumes. Mirrors the encode arm in
    /// `spawn_persistent_bridge_threads`'s writer.
    #[test]
    fn to_page_maps_to_persistent_browser_to_renderer_messages() {
        let nav = cv_ui::ToPage::Cmd {
            epoch: 7,
            cmd: "tb-link-click:0|||/path".into(),
        };
        let msg = match nav {
            cv_ui::ToPage::Cmd { epoch, cmd } => cv_ipc::Msg::NavCmd { epoch, cmd },
            _ => unreachable!(),
        };
        assert_eq!(
            msg,
            cv_ipc::Msg::NavCmd {
                epoch: 7,
                cmd: "tb-link-click:0|||/path".into()
            }
        );
        assert!(msg.is_valid_for_direction(cv_ipc::MsgDirection::BrowserToRenderer));

        let host = cv_ui::ToPage::Host {
            epoch: 9,
            command: cv_ui::HostCommand::SwitchTab(42),
        };
        let host_msg = match host {
            cv_ui::ToPage::Host { epoch, command } => cv_ipc::Msg::HostCmd {
                epoch,
                payload: frame_codec::encode_host_command(&command),
            },
            _ => unreachable!(),
        };
        match host_msg {
            cv_ipc::Msg::HostCmd { epoch, payload } => {
                assert_eq!(epoch, 9);
                match frame_codec::decode_host_command(&payload).expect("decode") {
                    cv_ui::HostCommand::SwitchTab(id) => assert_eq!(id, 42),
                    other => panic!("expected SwitchTab, got {other:?}"),
                }
            }
            other => panic!("expected HostCmd, got {other:?}"),
        }
    }

    /// Stale-epoch drop semantics, the race-free `nav_in_flight` replacement,
    /// survive the boundary because `epoch` rides on the `Msg::CommitFrame`
    /// envelope. Emulate the UI's guard: a frame whose epoch is older than
    /// the current navigation is dropped; an equal/newer one is applied.
    #[test]
    fn stale_commit_frame_epoch_is_dropped_newer_is_kept() {
        // The UI keeps a `current_epoch`; a Commit applies iff its epoch is
        // >= current (the in-process semantics; see FromPage::Commit docs).
        fn would_apply(current: u64, frame_epoch: u64) -> bool {
            frame_epoch >= current
        }
        // Nav advanced to epoch 5; a late frame from epoch 3 is stale.
        assert!(!would_apply(5, 3), "older epoch must be dropped");
        // The fresh frame for epoch 5 applies.
        assert!(would_apply(5, 5));
        // A newer epoch (resize during nav) also applies.
        assert!(would_apply(5, 6));
    }

    // ---- A2: cross-process persistent renderer (gated) ----------------

    /// Locate the REAL `conclave` binary (the one whose `real_main`
    /// dispatches `--type renderer`). The `cargo test` HARNESS binary lives
    /// in `target/<profile>/deps/`; the real binary is one directory up at
    /// `target/<profile>/conclave[.exe]`. A unit-test harness re-exec'd as
    /// `--type renderer` would just re-run the test runner (it never reaches
    /// `real_main`), so a cross-process test MUST drive the real binary, not
    /// `current_exe()`. Returns `None` (→ test skips) if it cannot be found,
    /// e.g. `cargo test` was run without first building the binary.
    #[cfg(target_os = "windows")]
    fn locate_real_tb_browser_exe() -> Option<String> {
        let test_exe = std::env::current_exe().ok()?;
        // .../target/<profile>/deps/<hash>.exe  →  .../target/<profile>/
        let profile_dir = test_exe.parent()?.parent()?;
        let candidate = profile_dir.join("conclave.exe");
        if candidate.is_file() {
            return candidate.to_str().map(str::to_string);
        }
        None
    }

    /// END-TO-END: spawn a REAL persistent renderer PROCESS (the actual
    /// `conclave --type renderer --persistent` binary), drive it with the
    /// persistent protocol, and assert a real page renders THROUGH the
    /// renderer process and a `CommitFrame` comes back. The child renders a
    /// local `file://` HTML page (parse + style + layout + paint), proving
    /// the !Send page graph lives in the child and only Send bytes cross the
    /// pipe. The first commit (epoch 0) is the initial paint; we assert its
    /// frame is a real, length-valid, non-empty bitmap.
    ///
    /// A WATCHDOG thread guarantees the test can never hang the suite: if the
    /// renderer wedges, the watchdog force-exits the process after a generous
    /// timeout. Skips cleanly (no spawn) when the real binary is absent.
    #[cfg(target_os = "windows")]
    #[test]
    fn persistent_renderer_process_renders_real_page_and_commits_frame() {
        // Opt-in: this spins up a real child process and is excluded from the
        // default fast unit run unless CV_A2_PROCESS_TEST=1. The in-process
        // `persistent_frame_marshals_end_to_end_over_message_pipe` proves the
        // same marshaling without a process and runs always.
        if std::env::var("CV_A2_PROCESS_TEST").as_deref() != Ok("1") {
            return;
        }
        let Some(exe) = locate_real_tb_browser_exe() else {
            return; // skip: real binary not built
        };

        // Hermetic page: a local temp file (no network).
        let dir = std::env::temp_dir();
        let path = dir.join(format!("tb_a2_persistent_{}.html", std::process::id()));
        std::fs::write(
            &path,
            b"<html><body><h1>Hello A2</h1><p>renderer process</p></body></html>",
        )
        .expect("write temp html");
        let nav = format!(
            "file:///{}",
            path.to_string_lossy().replace('\\', "/").trim_start_matches('/')
        );

        // Watchdog: the connect/handshake/read calls below block; if the real
        // renderer wedges, force the whole test process to exit so CI is not
        // hung indefinitely. 60s is far beyond a tiny page's cold-start.
        std::thread::Builder::new()
            .name("tb-a2-watchdog".into())
            .spawn(|| {
                std::thread::sleep(std::time::Duration::from_secs(60));
                eprintln!("[a2-test] watchdog fired: renderer wedged");
                std::process::exit(101);
            })
            .expect("spawn watchdog");

        let broker = std::sync::Arc::new(cv_content::broker::Broker::new());
        let host = BrowserRendererHost::spawn(
            &exe,
            broker.clone(),
            cv_ipc::renderer_host::site_for_url(&nav),
            Some(&nav),
            true, // persistent
        )
        .expect("spawn real persistent renderer");
        let BrowserRendererHost { session, child, .. } = host;
        let BrowserRendererSession { port, .. } = session;
        let child = child.expect("owned child");

        port.send(
            0,
            &cv_ipc::Msg::Handshake {
                protocol_version: cv_ipc::PROTOCOL_VERSION,
            },
        )
        .expect("send handshake");

        let mut got_frame = false;
        let mut acked = false;
        loop {
            match port.recv::<cv_ipc::Msg>() {
                Ok((_id, cv_ipc::Msg::HandshakeAck { renderer_version })) => {
                    assert!(cv_ipc::protocol_compatible(renderer_version));
                    acked = true;
                }
                Ok((_id, cv_ipc::Msg::CommitFrame { epoch, payload })) => {
                    assert_eq!(epoch, 0, "first commit is the initial paint (epoch 0)");
                    let frame = frame_codec::decode_frame(&payload).expect("decode initial frame");
                    assert!(frame.paint.bitmap.width >= 1);
                    assert!(frame.paint.bitmap.height >= 1);
                    assert_eq!(
                        frame.paint.bitmap.pixels.len(),
                        (frame.paint.bitmap.width as usize) * (frame.paint.bitmap.height as usize)
                    );
                    got_frame = true;
                    break;
                }
                Ok((_id, cv_ipc::Msg::LogLine { .. })) => {}
                Ok((_id, cv_ipc::Msg::ErrorMsg { message })) => {
                    panic!("renderer errored: {message}");
                }
                Ok((_id, _other)) => {}
                Err(_) => break, // pipe closed before a frame
            }
        }

        let _ = port.send(0, &cv_ipc::Msg::Shutdown);
        drop(child); // JobObject kill-on-close terminates the renderer
        let _ = std::fs::remove_file(&path);

        assert!(acked, "renderer must complete the handshake");
        assert!(got_frame, "persistent renderer must commit a real frame");
    }

    // ---- A3: SiteInstance routing + load-cancel ------------------------

    /// SiteInstance routing over the broker `RendererHost`: a same-site
    /// navigation reuses the existing child, a cross-site navigation allocates
    /// a NEW child, and releasing the last ref reports the teardown id. This
    /// is the allocator the `SiteRouter` drives; here we exercise it through
    /// `route_decision` exactly as the router does (no process).
    #[test]
    fn siteinstance_routing_reuses_same_site_and_swaps_cross_site() {
        use site_router::{RouteDecision, route_decision};

        // A tiny stand-in for SiteRouter's process map: site → child_id.
        let mut host = cv_ipc::renderer_host::RendererHost::new();
        let mut next_id = 100u32;
        let mut active_site: Option<String> = None;

        // Helper mirroring SiteRouter::ensure_renderer's id allocation.
        let mut ensure = |host: &mut cv_ipc::renderer_host::RendererHost,
                          site: &str,
                          next_id: &mut u32|
         -> u32 {
            if let Some(rec) = host.lookup(site) {
                let id = rec.child_id;
                let _ = host.lookup_or_spawn(site, || id);
                id
            } else {
                let id = *next_id;
                *next_id += 1;
                host.lookup_or_spawn(site, || id)
            }
        };

        // 1) First nav (example.com) → cross-site swap (no previous), spawns id.
        let d = route_decision("https://example.com/", active_site.as_deref());
        let example_id = match d {
            RouteDecision::CrossSiteSwap { site, previous_site, .. } => {
                assert_eq!(previous_site, None);
                let id = ensure(&mut host, &site, &mut next_id);
                active_site = Some(site);
                id
            }
            other => panic!("expected first swap, got {other:?}"),
        };

        // 2) Same-site nav (mail.example.com) → SameSite: the router routes to
        //    the ACTIVE renderer and does NOT touch refcounts (the tab still
        //    holds exactly one ref to example.com). Mirror that here — do NOT
        //    call `ensure`. The existing renderer must still be the same id.
        let d = route_decision("https://mail.example.com/inbox", active_site.as_deref());
        match d {
            RouteDecision::SameSite { site } => {
                assert_eq!(site, "https://example.com");
                let rec = host.lookup(&site).expect("site still mapped");
                assert_eq!(rec.child_id, example_id, "same-site nav must reuse the renderer");
            }
            other => panic!("expected same-site, got {other:?}"),
        }

        // 3) Cross-site nav (other.com) → swap, allocate a NEW id, release prev.
        let d = route_decision("https://other.com/x", active_site.as_deref());
        let other_id = match d {
            RouteDecision::CrossSiteSwap { site, previous_site, .. } => {
                assert_eq!(previous_site.as_deref(), Some("https://example.com"));
                let id = ensure(&mut host, &site, &mut next_id);
                // Release the previous site (single-tab → refcount hits 0 → teardown).
                assert_eq!(
                    host.release(previous_site.as_deref().unwrap()),
                    Some(example_id),
                    "releasing the last ref must report the old renderer for teardown"
                );
                active_site = Some(site);
                id
            }
            other => panic!("expected cross-site swap, got {other:?}"),
        };
        assert_ne!(other_id, example_id, "cross-site must use a distinct process");

        // 4) Input on the new active site → routes to active, no swap.
        assert_eq!(
            route_decision("tb-key:13", active_site.as_deref()),
            RouteDecision::SendToActive
        );
    }

    /// Two tabs/two sites: distinct sites get distinct renderers; a same-site
    /// second reference shares one. Drives the `RendererHost` exactly as the
    /// router does, asserting the process count.
    #[test]
    fn two_sites_get_two_renderers_one_site_shares() {
        let mut host = cv_ipc::renderer_host::RendererHost::new();
        let a = host
            .lookup_or_spawn_for_url("https://example.com/a", || 1)
            .unwrap();
        let b = host
            .lookup_or_spawn_for_url("https://other.org/b", || 2)
            .unwrap();
        // Same site as `a` (subdomain) → shares the renderer.
        let a2 = host
            .lookup_or_spawn_for_url("https://cdn.example.com/c", || 99)
            .unwrap();
        assert_eq!(a, a2, "same site shares the renderer");
        assert_ne!(a, b, "distinct sites use distinct renderers");
        assert_eq!(host.count(), 2);
    }

    /// LOAD-CANCEL (the Stop button made real), HARD tier, as a REAL process:
    /// spawn a renderer in its kill-on-close JobObject, then drop the owned
    /// process (the router's hard-kill primitive) and assert the child dies
    /// within the grace window. This is the cross-process backing of
    /// `SiteRouter::hard_kill_active`. Gated behind CV_A3_PROCESS_TEST so the
    /// default unit run never spawns a process; the routing-policy tests above
    /// cover the decision logic always.
    #[cfg(target_os = "windows")]
    #[test]
    fn load_cancel_hard_kill_terminates_renderer_process() {
        if std::env::var("CV_A3_PROCESS_TEST").as_deref() != Ok("1") {
            return;
        }
        let Some(exe) = locate_real_tb_browser_exe() else {
            return; // skip: real binary not built
        };

        // Watchdog so a wedged child can never hang the suite.
        std::thread::Builder::new()
            .name("tb-a3-watchdog".into())
            .spawn(|| {
                std::thread::sleep(std::time::Duration::from_secs(60));
                eprintln!("[a3-test] watchdog fired");
                std::process::exit(101);
            })
            .expect("spawn watchdog");

        let nav = "https://example.com/";
        let broker = std::sync::Arc::new(cv_content::broker::Broker::new());
        let host = BrowserRendererHost::spawn(
            &exe,
            broker.clone(),
            cv_ipc::renderer_host::site_for_url(nav),
            Some(nav),
            true,
        )
        .expect("spawn renderer");
        let BrowserRendererHost { session, child, .. } = host;
        let child = child.expect("owned child");
        let pid = session.child_pid;

        // The child is alive; its process handle should NOT signal yet.
        assert_eq!(
            child.process.try_wait_for(0).expect("try_wait"),
            None,
            "renderer should still be running before kill"
        );

        // HARD cancel: force-terminate (router's last-resort) then drop the
        // JobObject. Either path kills the child; assert it is gone promptly.
        child.process.kill(1).expect("terminate renderer");
        let code = child
            .process
            .try_wait_for(5_000)
            .expect("wait for renderer exit");
        assert!(code.is_some(), "renderer must die within the grace window");
        broker.mark_dead_with_reason(pid, cv_content::broker::ChildDeathReason::Crash);
        drop(child); // JobObject close (idempotent — already dead)
        assert_eq!(
            broker.death_reason(pid),
            Some(cv_content::broker::ChildDeathReason::Crash)
        );
    }

    // ---- A3: NON-BLOCKING cross-site swap (the deadlock fix) ------------

    /// Build a process-free `SiteRouter` wired to a merged channel we own, so
    /// the off-thread-swap state machine can be exercised deterministically
    /// without spawning a real renderer. `from_rx` collects emitted frames;
    /// `router_rx` collects any `RendererReady` a worker would post (none in
    /// these tests, which drive `handle_renderer_ready` directly).
    #[cfg(target_os = "windows")]
    #[allow(clippy::type_complexity)]
    fn test_router() -> (
        SiteRouter,
        std::sync::mpsc::Receiver<cv_ui::FromPage>,
        std::sync::mpsc::Sender<RouterMsg>,
        std::sync::mpsc::Receiver<RouterMsg>,
    ) {
        let (from_tx, from_rx) = std::sync::mpsc::channel::<cv_ui::FromPage>();
        let (router_tx, router_rx) = std::sync::mpsc::channel::<RouterMsg>();
        let broker = std::sync::Arc::new(cv_content::broker::Broker::new());
        let mut router = SiteRouter::new(
            "tb_browser_test".to_string(),
            broker,
            from_tx,
            cv_ui::PageHwnd::null_for_tests(),
        );
        router.self_tx = Some(router_tx.clone());
        (router, from_rx, router_tx, router_rx)
    }

    /// THE responsiveness guarantee: a cross-site swap to a NOT-yet-spawned
    /// site registers a pending swap and returns IMMEDIATELY (the router loop
    /// is never parked on a spawn), AND a second command processed right after
    /// also returns immediately — the loop stays live while the spawn is in
    /// flight. We register the pending swap directly (no real process) and then
    /// route a Resize to prove the loop keeps moving.
    #[cfg(target_os = "windows")]
    #[test]
    fn router_pending_swap_keeps_loop_responsive() {
        let (mut router, _from_rx, _tx, _rx) = test_router();
        // No renderer exists for this site yet → register a pending swap.
        let swap_id = router.register_pending_swap("https://example.com");
        assert!(router.pending.is_some(), "swap must be registered as pending");
        assert_eq!(router.pending.as_ref().unwrap().swap_id, swap_id);

        // While the swap is "in flight", a second command (Resize) must route
        // and return — the router is NOT blocked. With no active renderer the
        // resize is a no-op, but `route` must still return `true` promptly.
        let keep_going = router.route(cv_ui::ToPage::Resize {
            epoch: 1,
            w: 800,
            h: 600,
        });
        assert!(keep_going, "router stays responsive during a pending swap");
        // And a Stop arriving mid-swap routes too (does not block).
        let keep_going = router.route(cv_ui::ToPage::Cmd {
            epoch: 2,
            cmd: cv_ui::STOP_LOAD_CMD.to_string(),
        });
        assert!(keep_going, "Stop processed during a pending swap");
    }

    /// Stop DURING a pending swap cancels it: the pending marker flips to
    /// cancelled, and when the worker's `RendererReady` finally arrives it is
    /// DISCARDED (no renderer inserted, no active set) — the swap is aborted.
    #[cfg(target_os = "windows")]
    #[test]
    fn router_stop_cancels_pending_swap() {
        let (mut router, _from_rx, _tx, _rx) = test_router();
        let swap_id = router.register_pending_swap("https://example.com");

        // Stop arrives mid-spawn.
        router.handle_stop_load();
        assert!(
            router.pending.as_ref().is_some_and(|p| p.cancelled),
            "Stop must mark the pending swap cancelled"
        );

        // The worker eventually reports success — but it must be discarded
        // because the swap was cancelled. (We feed an Err result so no real
        // process/conn is needed; the discard branch is identical for Ok.)
        router.handle_renderer_ready(
            swap_id,
            "https://example.com".to_string(),
            "https://example.com/".to_string(),
            3,
            None,
            Err("cancelled-swap result".to_string()),
        );
        assert!(router.active.is_none(), "cancelled swap must not activate");
        assert!(router.renderers.is_empty(), "cancelled swap inserts nothing");
        assert!(router.pending.is_none(), "pending cleared after the result");
    }

    /// A SUPERSEDED swap (a newer navigation started before the older spawn
    /// finished) is discarded when its result arrives — only the latest swap
    /// wins, and stale results never clobber router state.
    #[cfg(target_os = "windows")]
    #[test]
    fn router_superseded_swap_result_is_discarded() {
        let (mut router, _from_rx, _tx, _rx) = test_router();
        let first = router.register_pending_swap("https://a.example.com");
        let second = router.register_pending_swap("https://b.example.com");
        assert_ne!(first, second, "each swap gets a fresh id");
        assert_eq!(
            router.pending.as_ref().unwrap().swap_id,
            second,
            "the newer swap supersedes the older as the pending one"
        );

        // The FIRST (superseded) swap's worker reports now — must be dropped.
        router.handle_renderer_ready(
            first,
            "https://a.example.com".to_string(),
            "https://a.example.com/".to_string(),
            5,
            None,
            Err("stale".to_string()),
        );
        assert!(router.active.is_none());
        assert!(router.renderers.is_empty());
        assert_eq!(
            router.pending.as_ref().unwrap().swap_id,
            second,
            "the still-pending newer swap must survive a stale result"
        );
    }

    /// A spawn FAILURE (the live, non-superseded swap returns Err) surfaces an
    /// error frame to the window instead of hanging — the window leaves the
    /// loading state. Proves the handshake/spawn-timeout path ends in an
    /// honest frame, never an indefinite wait.
    #[cfg(target_os = "windows")]
    #[test]
    fn router_spawn_failure_emits_error_frame() {
        let (mut router, from_rx, _tx, _rx) = test_router();
        let swap_id = router.register_pending_swap("https://dead.example.com");
        router.handle_renderer_ready(
            swap_id,
            "https://dead.example.com".to_string(),
            "https://dead.example.com/".to_string(),
            7,
            None,
            Err("persistent handshake timed out after 10000 ms".to_string()),
        );
        assert!(router.pending.is_none(), "failed swap clears pending");
        assert!(router.active.is_none());
        // An error frame for the failed nav must have been emitted.
        let frame = from_rx
            .try_recv()
            .expect("spawn failure must emit an error frame, not hang");
        match frame {
            cv_ui::FromPage::Commit { epoch, .. } => {
                assert_eq!(epoch, 7, "error frame carries the nav epoch");
            }
        }
    }

    // ---- A1: renderer entry argv parsing -------------------------------

    #[test]
    fn parse_renderer_args_reads_pipe_name_as_last_positional() {
        // SandboxedChild::spawn appends the pipe name as the final
        // positional; the child must find it there.
        let cli = Cli::parse_from(["conclave", "--type", "renderer", "tbrm_renderer_1234_a"]);
        let args = parse_renderer_args(&cli).expect("parse");
        assert_eq!(args.pipe_name, "tbrm_renderer_1234_a");
        assert_eq!(args.site, None);
        assert_eq!(args.initial_nav, None);
    }

    #[test]
    fn parse_renderer_args_reads_site_and_initial_nav_flags() {
        let cli = Cli::parse_from([
            "conclave",
            "--type",
            "renderer",
            "--site",
            "https://example.com",
            "--initial-nav",
            "https://example.com/page",
            "tbrm_renderer_42_b",
        ]);
        let args = parse_renderer_args(&cli).expect("parse");
        assert_eq!(args.pipe_name, "tbrm_renderer_42_b");
        assert_eq!(args.site.as_deref(), Some("https://example.com"));
        assert_eq!(
            args.initial_nav.as_deref(),
            Some("https://example.com/page")
        );
    }

    #[test]
    fn parse_renderer_args_missing_pipe_name_is_error() {
        // Only flags, no positional pipe name.
        let cli = Cli::parse_from(["conclave", "--type", "renderer"]);
        // "renderer" is consumed as the value of --type, so there is no
        // trailing positional. The parser must reject it.
        assert!(parse_renderer_args(&cli).is_err());
    }

    #[test]
    fn parse_renderer_args_empty_pipe_name_is_error() {
        let cli = Cli::parse_from(["conclave", "--type", "renderer", ""]);
        assert!(parse_renderer_args(&cli).is_err());
    }

    #[test]
    fn renderer_child_args_round_trip_through_parser() {
        // The browser builds argv (sans pipe name), spawn appends the
        // pipe name; the child parses it back. Producer and consumer
        // must agree on the wire shape — prove it without a process.
        let mut argv = build_renderer_child_args(
            Some("https://example.com"),
            Some("https://example.com/start"),
            false,
        );
        argv.push("tbrm_renderer_777_c".into()); // spawn appends pipe name last

        // Re-parse from a full command line (program + argv).
        let mut full = vec!["conclave".to_string()];
        full.extend(argv);
        let cli = Cli::parse_from(full);
        let parsed = parse_renderer_args(&cli).expect("parse");
        assert_eq!(parsed.pipe_name, "tbrm_renderer_777_c");
        assert_eq!(parsed.site.as_deref(), Some("https://example.com"));
        assert_eq!(
            parsed.initial_nav.as_deref(),
            Some("https://example.com/start")
        );
        assert!(!parsed.persistent);
    }

    #[test]
    fn renderer_child_args_persistent_flag_round_trips() {
        let mut argv = build_renderer_child_args(
            Some("https://example.com"),
            Some("https://example.com/start"),
            true,
        );
        assert!(
            argv.iter().any(|a| a == "--persistent"),
            "persistent argv must carry --persistent: {argv:?}"
        );
        argv.push("tbrm_renderer_888_p".into());
        let mut full = vec!["conclave".to_string()];
        full.extend(argv);
        let cli = Cli::parse_from(full);
        let parsed = parse_renderer_args(&cli).expect("parse");
        assert!(parsed.persistent);
        assert_eq!(parsed.pipe_name, "tbrm_renderer_888_p");
        assert_eq!(parsed.initial_nav.as_deref(), Some("https://example.com/start"));
    }

    #[test]
    fn renderer_child_args_omit_empty_site_and_nav() {
        let argv = build_renderer_child_args(None, None, false);
        assert_eq!(argv, vec!["--type".to_string(), "renderer".to_string()]);
        let argv2 = build_renderer_child_args(Some(""), Some(""), false);
        assert_eq!(argv2, vec!["--type".to_string(), "renderer".to_string()]);
    }

    // ---- A1: protocol-version handshake negotiation --------------------

    #[test]
    fn renderer_negotiates_matching_protocol_version() {
        // Browser opens with the current PROTOCOL_VERSION; renderer must
        // accept and ack with the version it speaks.
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        browser_ep
            .send(
                0,
                &cv_ipc::Msg::Handshake {
                    protocol_version: cv_ipc::PROTOCOL_VERSION,
                },
            )
            .expect("send handshake");

        let outcome = renderer_negotiate_handshake(&renderer_ep).expect("negotiate");
        assert_eq!(
            outcome,
            RendererHandshake::Negotiated {
                browser_version: cv_ipc::PROTOCOL_VERSION
            }
        );

        // The renderer must have acked with the version it speaks.
        let (_id, ack): (u32, cv_ipc::Msg) = browser_ep.try_recv().expect("recv ack");
        assert_eq!(
            ack,
            cv_ipc::Msg::HandshakeAck {
                renderer_version: cv_ipc::PROTOCOL_VERSION
            }
        );
    }

    #[test]
    fn renderer_rejects_incompatible_protocol_version() {
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        browser_ep
            .send(
                0,
                &cv_ipc::Msg::Handshake {
                    protocol_version: cv_ipc::PROTOCOL_VERSION + 1,
                },
            )
            .expect("send handshake");

        let err = renderer_negotiate_handshake(&renderer_ep)
            .expect_err("incompatible version must fail");
        assert!(err.contains("protocol mismatch"), "got: {err}");

        // The renderer must have told the browser WHY (an honest error,
        // not a silent drop or a fake ack).
        let (_id, reply): (u32, cv_ipc::Msg) = browser_ep.try_recv().expect("recv error reply");
        match reply {
            cv_ipc::Msg::ErrorMsg { message } => {
                assert!(message.contains("version mismatch"), "got: {message}");
            }
            other => panic!("expected ErrorMsg, got {other:?}"),
        }
    }

    #[test]
    fn renderer_rejects_non_handshake_opening_message() {
        // A LayoutRequest arriving before the handshake is a protocol
        // violation; the renderer must reject it, not render.
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        browser_ep
            .send(
                0,
                &cv_ipc::Msg::LayoutRequest {
                    url: "https://example.com/".into(),
                    viewport_w: 100,
                    viewport_h: 100,
                    html: b"<p>x</p>".to_vec(),
                },
            )
            .expect("send layout");

        let err = renderer_negotiate_handshake(&renderer_ep)
            .expect_err("non-handshake opener must fail");
        assert!(err.contains("non-handshake"), "got: {err}");
    }

    #[test]
    fn renderer_handshake_shutdown_before_ready_is_clean_exit() {
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        browser_ep
            .send(0, &cv_ipc::Msg::Shutdown)
            .expect("send shutdown");
        let outcome = renderer_negotiate_handshake(&renderer_ep).expect("clean exit");
        assert_eq!(outcome, RendererHandshake::ShutdownBeforeReady);
    }

    #[test]
    fn full_handshake_round_trip_browser_and_renderer_negotiate_then_paint() {
        // End-to-end over the in-process MessagePipe: the browser host
        // sends its handshake + a layout request; the renderer side
        // negotiates the version, then renders a REAL page and replies
        // PaintReady. Proves the A1 handshake + request/response round
        // trips without a spawned process.
        let (browser_ep, renderer_ep) = cv_ipc::MessagePipe::new();
        let broker = test_renderer_broker(222);
        let mut host = BrowserRendererHost::new(
            222,
            broker.clone(),
            browser_ep,
            Some("https://example.com".into()),
        );

        // Browser drives the protocol.
        host.send_handshake(cv_ipc::PROTOCOL_VERSION)
            .expect("send handshake");
        host.request_layout(
            "https://example.com/".into(),
            120,
            80,
            b"<html><body><p>hello</p></body></html>".to_vec(),
        )
        .expect("send layout");

        // Renderer negotiates the handshake, then services the request.
        let outcome = renderer_negotiate_handshake(&renderer_ep).expect("renderer negotiate");
        assert_eq!(
            outcome,
            RendererHandshake::Negotiated {
                browser_version: cv_ipc::PROTOCOL_VERSION
            }
        );
        let (_id, req): (u32, cv_ipc::Msg) = renderer_ep.try_recv().expect("recv layout request");
        let (w, h, bgra) = match req {
            cv_ipc::Msg::LayoutRequest {
                url,
                viewport_w,
                viewport_h,
                html,
            } => paint_layout_request(&html, &url, viewport_w, viewport_h),
            other => panic!("expected LayoutRequest, got {other:?}"),
        };
        // A real page render: non-empty, length-valid BGRA buffer.
        assert!(w > 0 && h > 0, "renderer produced a sized frame");
        assert_eq!(bgra.len(), (w as usize) * (h as usize) * 4);
        renderer_ep
            .send(
                0,
                &cv_ipc::Msg::PaintReady {
                    width: w,
                    height: h,
                    bitmap_bgra: bgra.clone(),
                },
            )
            .expect("send paint ready");

        // Browser consumes the handshake ack + paint, verifying versions.
        assert_eq!(
            host.recv_event().expect("recv ack"),
            Some(BrowserRendererEvent::HandshakeAck {
                renderer_version: cv_ipc::PROTOCOL_VERSION
            })
        );
        match host.recv_event().expect("recv paint") {
            Some(BrowserRendererEvent::PaintReady {
                width,
                height,
                bitmap_bgra,
            }) => {
                assert_eq!((width, height), (w, h));
                assert_eq!(bitmap_bgra, bgra);
            }
            other => panic!("expected PaintReady, got {other:?}"),
        }
        assert_eq!(broker.death_reason(222), None);
    }

