    #[test]
    fn pick_img_src_uses_picture_source_srcset() {
        let html = cv_html::parse(
            "<picture><source srcset=\"small.webp 320w, hero.webp 1200w\"><img width=\"900\"></picture>",
        );
        // Content is under the (now always-synthesized) <body>.
        let body = html
            .root
            .children
            .iter()
            .find(|n| matches!(&n.kind, cv_html::NodeKind::Element { name, .. } if name == "body"))
            .expect("body");
        let picture = body
            .children
            .iter()
            .find(
                |n| matches!(&n.kind, cv_html::NodeKind::Element { name, .. } if name == "picture"),
            )
            .expect("picture");
        let img = picture
            .children
            .iter()
            .find(|n| matches!(&n.kind, cv_html::NodeKind::Element { name, .. } if name == "img"))
            .expect("img");
        let picked = pick_img_src(img, &[picture], 1024.0);
        assert_eq!(picked.as_deref(), Some("hero.webp"));
    }

    #[test]
    fn lower_style_keeps_animated_zero_opacity_content_visible() {
        let cs = cv_css::cascade::ComputedStyle {
            opacity: Some(0.0),
            has_animation: true,
            ..cv_css::cascade::ComputedStyle::default()
        };
        let style = lower_style(&cs, &cv_layout::LayoutConfig::default(), 16.0);
        assert_eq!(style.opacity, Some(1.0));

        let cs_static = cv_css::cascade::ComputedStyle {
            opacity: Some(0.0),
            has_animation: false,
            ..cv_css::cascade::ComputedStyle::default()
        };
        let static_style = lower_style(&cs_static, &cv_layout::LayoutConfig::default(), 16.0);
        assert_eq!(static_style.opacity, Some(0.0));
    }

    #[test]
    fn lower_style_defers_percent_translate_until_layout_box_size_is_known() {
        let cs = cv_css::cascade::ComputedStyle {
            width: Some(cv_css::properties::Length::Px(450.0)),
            height: Some(cv_css::properties::Length::Px(450.0)),
            translate_x: Some(cv_css::properties::Length::Percent(-50.0)),
            translate_y: Some(cv_css::properties::Length::Percent(-50.0)),
            ..cv_css::cascade::ComputedStyle::default()
        };
        let style = lower_style(&cs, &cv_layout::LayoutConfig::default(), 16.0);
        assert_eq!(style.translate_x_px, Some(0.0));
        assert_eq!(style.translate_y_px, Some(0.0));
        assert_eq!(style.translate_x_percent, Some(-50.0));
        assert_eq!(style.translate_y_percent, Some(-50.0));
    }

    /// Regression test for Chrome-divergence #1 (Conclave):
    /// `rem` and `em` must resolve against the live root / parent
    /// font-size, not the hardcoded literal 16. Before this fix,
    /// every Tailwind site whose root font-size was anything other
    /// than 16 (or whose nested elements used `em`) mis-sized their
    /// widths/paddings — most visibly, `w-64` (16rem) sidebars came
    /// out as plain-element-fills because the cascade saw 16 * 16 =
    /// 256 against the wrong reference.
    #[test]
    fn lower_style_resolves_rem_against_root_font_size() {
        // Pretend the root <html> set font-size to 10px (common
        // Tailwind reset target so `rem` reads as "tens").
        set_root_font_size_px(10.0);
        let cs = cv_css::cascade::ComputedStyle {
            width: Some(cv_css::properties::Length::Rem(16.0)),
            ..cv_css::cascade::ComputedStyle::default()
        };
        let style = lower_style(&cs, &cv_layout::LayoutConfig::default(), 16.0);
        // 16rem against a 10px root must be 160 — NOT 256.
        match style.width {
            Some(cv_layout::LengthSpec::Px(px)) => assert!(
                (px - 160.0).abs() < 0.01,
                "16rem against root=10 should be 160px, got {px}"
            ),
            other => panic!("expected Px(160), got {other:?}"),
        }
        // Restore the default so other tests aren't affected.
        set_root_font_size_px(16.0);
    }

    #[test]
    fn lower_style_resolves_em_against_parent_font_size() {
        // Parent font-size 20px → child padding 1em should be 20.
        let cs = cv_css::cascade::ComputedStyle {
            padding: [
                Some(cv_css::properties::Length::Em(1.0)),
                Some(cv_css::properties::Length::Em(1.0)),
                Some(cv_css::properties::Length::Em(1.0)),
                Some(cv_css::properties::Length::Em(1.0)),
            ],
            ..cv_css::cascade::ComputedStyle::default()
        };
        let style = lower_style(&cs, &cv_layout::LayoutConfig::default(), 20.0);
        assert!((style.padding.top - 20.0).abs() < 0.01);
        assert!((style.padding.right - 20.0).abs() < 0.01);
        assert!((style.padding.bottom - 20.0).abs() < 0.01);
        assert!((style.padding.left - 20.0).abs() < 0.01);
    }

