    #[test]
    fn document_fragment_appends_children_without_wrapper_node() {
        let html = "<!doctype html><html><body><div id='host'></div><script>var frag=document.createDocumentFragment();var first=document.createElement('span');first.setAttribute('id','first');first.append('A');frag.appendChild(first);frag.append('B');var copy=frag.cloneNode(true);document.getElementById('host').appendChild(copy);</script></body></html>";
        let cfg = cv_layout::LayoutConfig::default();
        let (_runtime, doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");

        fn find_element_by_id<'a>(
            node: &'a cv_html::Node,
            wanted_id: &str,
        ) -> Option<&'a cv_html::Node> {
            if let cv_html::NodeKind::Element { attrs, .. } = &node.kind {
                if attrs.iter().any(|a| a.name == "id" && a.value == wanted_id) {
                    return Some(node);
                }
            }
            for child in &node.children {
                if let Some(found) = find_element_by_id(child, wanted_id) {
                    return Some(found);
                }
            }
            None
        }

        let host = find_element_by_id(&doc.root, "host").expect("host exists");
        assert_eq!(
            host.children.len(),
            2,
            "fragment should flatten into host children"
        );
        assert!(
            matches!(&host.children[0].kind, cv_html::NodeKind::Element { name, .. } if name == "span")
        );
        assert!(matches!(&host.children[1].kind, cv_html::NodeKind::Text(text) if text == "B"));
        assert!(
            find_element_by_id(&doc.root, "first").is_some(),
            "fragment child should survive append"
        );
    }

    #[test]
    fn before_and_after_insert_around_existing_node() {
        let html = "<!doctype html><html><body><div id='parent'><span id='mid'>M</span></div><script>var mid=document.getElementById('mid');mid.before('A');mid.after('B');</script></body></html>";
        let cfg = cv_layout::LayoutConfig::default();
        let (_runtime, doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");

        fn find_text_for_id(node: &cv_html::Node, wanted_id: &str) -> Option<String> {
            if let cv_html::NodeKind::Element { attrs, .. } = &node.kind {
                let is_match = attrs.iter().any(|a| a.name == "id" && a.value == wanted_id);
                if is_match {
                    let mut text = String::new();
                    for child in &node.children {
                        match &child.kind {
                            cv_html::NodeKind::Text(s) => text.push_str(s),
                            cv_html::NodeKind::Element { .. } => {
                                for grandchild in &child.children {
                                    if let cv_html::NodeKind::Text(s) = &grandchild.kind {
                                        text.push_str(s);
                                    }
                                }
                            }
                            _ => {}
                        }
                    }
                    return Some(text);
                }
            }
            for child in &node.children {
                if let Some(found) = find_text_for_id(child, wanted_id) {
                    return Some(found);
                }
            }
            None
        }

        assert_eq!(
            find_text_for_id(&doc.root, "parent").as_deref(),
            Some("AMB")
        );
    }

