    #[test]
    fn event_listener_signal_abort_removes_listener() {
        let doc =
            cv_html::parse("<!doctype html><html><body><button id='b'>x</button></body></html>");
        let mut runtime = LiveInterp::new(&doc, "https://example.com/");
        runtime
            .interp
            .run(
                "window.__n = 0;\
                 window.__sig = { aborted: false };\
                 document.getElementById('b').addEventListener('click', function(){ window.__n += 1; }, { signal: window.__sig });",
            )
            .expect("setup");
        let b_path = {
            let t = runtime.table.borrow();
            t.all
                .iter()
                .find(|r| r.id.as_deref() == Some("b"))
                .map(|r| r.path.clone())
                .unwrap()
        };
        runtime.dispatch_click(&b_path);
        assert_eq!(
            window_str(&runtime, "__n"),
            "1",
            "listener fires while signal is live"
        );
        runtime
            .interp
            .run("window.__sig.aborted = true;")
            .expect("abort");
        runtime.dispatch_click(&b_path);
        assert_eq!(
            window_str(&runtime, "__n"),
            "1",
            "aborted-signal listener no longer fires"
        );
    }

    #[test]
    fn keydown_fires_on_focused_element_and_bubbles() {
        // A keydown listener on a focused <input> (and on its ancestor form)
        // must fire, with event.target = the focused element. Previously
        // keyboard events only reached the document/window (empty-path)
        // bucket, so per-element and framework-app-root key handlers — Enter-
        // to-submit, Escape-to-close, arrow-key nav — never ran.
        let doc = cv_html::parse(
            "<!doctype html><html><body><form id='f'><input id='i'></form></body></html>",
        );
        let mut runtime = LiveInterp::new(&doc, "https://example.com/");
        runtime
            .interp
            .run(
                "window.__k = ''; window.__t = ''; window.__bubbled = false;\
                 document.getElementById('i').addEventListener('keydown', function(e){ \
                     window.__k = e.key; window.__t = (e.target && e.target.id) || ''; });\
                 document.getElementById('f').addEventListener('keydown', function(){ \
                     window.__bubbled = true; });",
            )
            .expect("setup script runs");

        let i_path = {
            let t = runtime.table.borrow();
            t.all
                .iter()
                .find(|r| r.id.as_deref() == Some("i"))
                .map(|r| r.path.clone())
                .expect("#i present in element table")
        };

        let fired = runtime.dispatch_keyboard_event_with_mods(
            "keydown",
            "Enter",
            "Enter",
            false,
            false,
            false,
            false,
            Some(&i_path),
        );
        assert!(fired, "keydown should fire on the focused element");

        let read = |k: &str| {
            runtime
                .interp
                .get_global("window")
                .and_then(|w| match w {
                    cv_js::Value::Object(o) => o.borrow().get(k).cloned(),
                    _ => None,
                })
                .map(|v| v.to_display_string())
                .unwrap_or_default()
        };
        assert_eq!(read("__k"), "Enter", "handler sees event.key");
        assert_eq!(read("__t"), "i", "event.target is the focused element");
        assert_eq!(
            read("__bubbled"),
            "true",
            "keydown bubbles to the ancestor <form> listener"
        );
    }

    #[test]
    fn click_listener_fires_after_insert_before_sibling() {
        // Regression guard for identity-stable event dispatch: a click
        // listener registered on #a must still fire after a sibling is
        // inserted before it. This currently passes because both the
        // registration and the dispatch resolve through the same
        // persistent element table. NOTE: the harder roadmap-#3 case —
        // a listener registered against the *persistent* table while the
        // click hit-test runs against the *per-render layout* tree
        // (whose paths diverge after a re-render) — is the real "re-key
        // event_listeners by node id" gap and is NOT exercised here.
        let doc = cv_html::parse("<!doctype html><html><body><div id='a'>A</div></body></html>");
        let mut runtime = LiveInterp::new(&doc, "https://example.com/");
        runtime
            .interp
            .run(
                "window.__hit = 0; \
                 var a = document.getElementById('a'); \
                 a.addEventListener('click', function(){ window.__hit = window.__hit + 1; }); \
                 var nu = document.createElement('div'); \
                 document.body.insertBefore(nu, a);",
            )
            .expect("setup script runs");

        // Resolve #a's CURRENT path in the table (after the insert-before
        // shifted it). A real click hit-tests against the live layout, so
        // dispatch must target this current path.
        let a_path = {
            let t = runtime.table.borrow();
            t.all
                .iter()
                .find(|r| r.id.as_deref() == Some("a"))
                .map(|r| r.path.clone())
                .expect("#a present in element table")
        };

        runtime.dispatch_click(&a_path);

        let hit = runtime
            .interp
            .get_global("window")
            .and_then(|w| match w {
                cv_js::Value::Object(o) => o.borrow().get("__hit").cloned(),
                _ => None,
            })
            .map(|v| v.to_display_string())
            .unwrap_or_default();
        assert_eq!(
            hit, "1",
            "click listener registered on #a must fire on #a at its new path \
             (path index after insert-before = {a_path:?})"
        );
    }

