    #[test]
    fn clamp_widths_survive_into_layout() {
        let html = "<!doctype html><html><head><style>html,body{margin:0;padding:0}section{width:clamp(200px,50vw,400px);height:20px}aside{width:clamp(200px,10vw,400px);height:20px}</style></head><body><section>wide</section><aside>narrow</aside></body></html>";
        let cfg = cv_layout::LayoutConfig::default();
        let (_runtime, _doc, _sheets, paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");
        let root = paint.layout_root.as_ref().expect("layout root");

        fn find_box<'a>(
            node: &'a cv_layout::LayoutBox,
            tag: &str,
        ) -> Option<&'a cv_layout::LayoutBox> {
            if matches!(&node.kind, cv_layout::BoxKind::Block { tag: t } if t == tag) {
                return Some(node);
            }
            for child in &node.children {
                if let Some(found) = find_box(child, tag) {
                    return Some(found);
                }
            }
            None
        }

        let section = find_box(root, "section").expect("section box");
        let aside = find_box(root, "aside").expect("aside box");
        assert!(
            (section.content.w - 400.0).abs() < 1.0,
            "section width should clamp to max, got {}",
            section.content.w
        );
        assert!(
            (aside.content.w - 200.0).abs() < 1.0,
            "aside width should clamp to min, got {}",
            aside.content.w
        );
    }

    #[test]
    fn flex_shorthand_basis_survives_into_layout() {
        let html = "<!doctype html><html><head><style>html,body{margin:0;padding:0}#row{display:flex;column-gap:10px}#row>div{height:20px}#a{flex:0 0 120px}#b{flex:0 0 80px}</style></head><body><div id='row'><div id='a'>A</div><div id='b'>B</div></div></body></html>";
        let cfg = cv_layout::LayoutConfig::default();
        let (_runtime, _doc, _sheets, paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");
        let root = paint.layout_root.as_ref().expect("layout root");

        fn find_box<'a>(
            node: &'a cv_layout::LayoutBox,
            tag: &str,
        ) -> Option<&'a cv_layout::LayoutBox> {
            if matches!(&node.kind, cv_layout::BoxKind::Block { tag: t } if t == tag) {
                return Some(node);
            }
            for child in &node.children {
                if let Some(found) = find_box(child, tag) {
                    return Some(found);
                }
            }
            None
        }

        let row = find_box(root, "div").expect("row box");
        assert!(row.children.len() >= 2, "row should have flex children");
        assert!(
            (row.children[0].content.w - 120.0).abs() < 1.0,
            "first child width should come from flex-basis, got {}",
            row.children[0].content.w
        );
        assert!(
            (row.children[1].content.w - 80.0).abs() < 1.0,
            "second child width should come from flex-basis, got {}",
            row.children[1].content.w
        );
        assert!(
            row.children[1].content.x >= row.children[0].content.x + 129.0,
            "second child should be placed after the basis width + gap, got {}",
            row.children[1].content.x
        );
    }

