    #[test]
    fn calc_widths_keep_percentage_until_layout() {
        let html = "<!doctype html><html><head><style>html,body{margin:0;padding:0}#outer{width:400px}#inner{width:calc(50% - 20px);height:20px}</style></head><body><div id='outer'><div id='inner'></div></div></body></html>";
        let cfg = cv_layout::LayoutConfig::default();
        let (_runtime, _doc, _sheets, paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");
        let root = paint.layout_root.as_ref().expect("layout root");

        fn find_boxes<'a>(
            node: &'a cv_layout::LayoutBox,
            tag: &str,
            out: &mut Vec<&'a cv_layout::LayoutBox>,
        ) {
            if matches!(&node.kind, cv_layout::BoxKind::Block { tag: t } if t == tag) {
                out.push(node);
            }
            for child in &node.children {
                find_boxes(child, tag, out);
            }
        }

        let mut divs = Vec::new();
        find_boxes(root, "div", &mut divs);
        assert!(divs.len() >= 2, "expected outer and inner div boxes");
        assert!(
            (divs[0].content.w - 400.0).abs() < 1.0,
            "outer width should be 400px, got {}",
            divs[0].content.w
        );
        assert!(
            (divs[1].content.w - 180.0).abs() < 1.0,
            "inner width should resolve calc(50% - 20px) against the outer width, got {}",
            divs[1].content.w
        );
    }

