    #[test]
    fn user_agent_table_defaults_preserve_table_layout() {
        let html = "<!doctype html><html><body><table><thead><tr><th>Block</th><th>Hash</th><th>Age</th></tr></thead><tbody><tr><td>1</td><td>0xabc</td><td>now</td></tr></tbody></table></body></html>";
        let cfg = cv_layout::LayoutConfig::default();
        let (_runtime, _doc, _sheets, paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");
        let root = paint.layout_root.as_ref().expect("layout root");

        fn find_table<'a>(node: &'a cv_layout::LayoutBox) -> Option<&'a cv_layout::LayoutBox> {
            if matches!(&node.kind, cv_layout::BoxKind::Block { tag } if tag == "table") {
                return Some(node);
            }
            for child in &node.children {
                if let Some(found) = find_table(child) {
                    return Some(found);
                }
            }
            None
        }

        let table = find_table(root).expect("table");
        let thead = table
            .children
            .iter()
            .find(
                |child| matches!(&child.kind, cv_layout::BoxKind::Block { tag } if tag == "thead"),
            )
            .expect("thead");
        let row = thead
            .children
            .iter()
            .find(|child| matches!(&child.kind, cv_layout::BoxKind::Block { tag } if tag == "tr"))
            .expect("header row");
        assert!(
            row.children.len() >= 3,
            "header row should expose table cells, got {}",
            row.children.len()
        );
        let first_x = row.children[0].content.x;
        let second_x = row.children[1].content.x;
        let third_x = row.children[2].content.x;
        assert!(
            second_x > first_x + 50.0,
            "second header cell should be to the right of the first, got {} vs {}",
            second_x,
            first_x
        );
        assert!(
            third_x > second_x + 50.0,
            "third header cell should be to the right of the second, got {} vs {}",
            third_x,
            second_x
        );
    }

