    #[test]
    fn ua_inline_spans_do_not_stack_vertically() {
        let html = "<!doctype html><html><body><div id='brand'><span id='left'>HYVE</span><span id='right'>CHAIN</span></div></body></html>";
        let cfg = cv_layout::LayoutConfig::default();
        let (_runtime, doc, _sheets, paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");
        let root = paint.layout_root.as_ref().expect("layout root");
        let ids = build_id_map(&doc.root);
        let index = build_path_to_box_index(root);
        let left = index
            .get(ids.get("left").expect("left path"))
            .expect("left box");
        let right = index
            .get(ids.get("right").expect("right path"))
            .expect("right box");
        assert!(
            (left.content.y - right.content.y).abs() < 1.0,
            "inline spans should share a line, got left y={} right y={}",
            left.content.y,
            right.content.y
        );
        assert!(
            right.content.x > left.content.x,
            "second inline span should sit to the right of the first, got left x={} right x={}",
            left.content.x,
            right.content.x
        );
    }

    #[test]
    fn svg_use_resolves_local_defs_and_offsets_shapes() {
        fn find_tag<'a>(
            node: &'a cv_layout::StyledNode,
            tag_name: &str,
        ) -> Option<&'a cv_layout::StyledNode> {
            if matches!(&node.kind, cv_layout::StyledKind::Element { tag } if tag == tag_name) {
                return Some(node);
            }
            for child in &node.children {
                if let Some(found) = find_tag(child, tag_name) {
                    return Some(found);
                }
            }
            None
        }

        let html = cv_html::parse(
            "<!doctype html><html><body><svg style='color:#00ff00' width='8' height='8' viewBox='0 0 8 8'><defs><g id='dot'><rect width='2' height='2' fill='currentColor'></rect></g></defs><use href='#dot' x='4' y='3'></use></svg></body></html>",
        );
        let sheets = vec![parse_user_agent_stylesheet()];
        let styled = build_styled_tree(
            &html.root,
            &[],
            &sheets,
            &cv_layout::LayoutConfig::default(),
            None,
            None,
        );

        let svg = find_tag(&styled, "svg").expect("svg node");
        let embedded = svg.style.embedded_image.as_ref().expect("svg rasterized");
        let moved = embedded.pixels[3 * embedded.width as usize + 4];
        let untouched = embedded.pixels[0];
        assert_ne!(
            (moved >> 24) & 0xFF,
            0,
            "use target should render at offset"
        );
        assert_eq!(
            (untouched >> 24) & 0xFF,
            0,
            "defs content should not render at origin without use"
        );
    }

    // ---- Bug-fix: parse_canvas_color ----

    /// Bug 3: parse_canvas_color now delegates to the full CSS Color Level 4
    /// parser: 148 named colors, rgb() with percentages, hsl(), rgba() float alpha.
    /// Returns None for invalid colors (per spec: ignore invalid fillStyle).
    #[test]
    fn parse_canvas_color_named_colors() {
        let orange = parse_canvas_color("orange").expect("orange");
        assert_eq!((orange.r, orange.g, orange.b, orange.a), (255, 165, 0, 255), "orange");

        let gray = parse_canvas_color("gray").expect("gray");
        assert_eq!((gray.r, gray.g, gray.b), (128, 128, 128), "gray");

        let grey = parse_canvas_color("grey").expect("grey");
        assert_eq!((grey.r, grey.g, grey.b), (128, 128, 128), "grey British spelling");

        let purple = parse_canvas_color("purple").expect("purple");
        assert_eq!((purple.r, purple.g, purple.b), (128, 0, 128), "purple");

        let cyan = parse_canvas_color("cyan").expect("cyan");
        assert_eq!((cyan.r, cyan.g, cyan.b, cyan.a), (0, 255, 255, 255), "cyan");

        let magenta = parse_canvas_color("magenta").expect("magenta");
        assert_eq!((magenta.r, magenta.g, magenta.b), (255, 0, 255), "magenta");

        let transparent = parse_canvas_color("transparent").expect("transparent");
        assert_eq!(transparent.a, 0, "transparent a=0");

        // Invalid color strings must return None (previous value kept by caller).
        assert!(parse_canvas_color("not-a-color").is_none(), "invalid color → None");
        assert!(parse_canvas_color("").is_none(), "empty string → None");
    }

    #[test]
    fn parse_canvas_color_rgb_percentages() {
        // 50% of 255 = 127.5; the CSS parser rounds to 127.
        let c = parse_canvas_color("rgb(100%, 50%, 0%)").expect("rgb%");
        assert_eq!((c.r, c.b, c.a), (255, 0, 255), "rgb% r/b/a channels");
        assert!((c.g as i32 - 128).abs() <= 1, "rgb% g ~127-128, got {}", c.g);

        let c2 = parse_canvas_color("rgb(0%, 0%, 100%)").expect("rgb% blue");
        assert_eq!((c2.r, c2.g, c2.b), (0, 0, 255), "rgb% blue");
    }

    #[test]
    fn parse_canvas_color_rgba_float_alpha() {
        let c = parse_canvas_color("rgba(255, 0, 0, 0.5)").expect("rgba");
        assert_eq!(c.r, 255);
        assert_eq!(c.g, 0);
        assert_eq!(c.b, 0);
        assert!((c.a as i32 - 128).abs() <= 2, "0.5 alpha ~128, got {}", c.a);
    }

    #[test]
    fn parse_canvas_color_hsl() {
        let red = parse_canvas_color("hsl(0, 100%, 50%)").expect("hsl red");
        assert_eq!((red.r, red.g, red.b, red.a), (255, 0, 0, 255), "hsl red");

        let lime = parse_canvas_color("hsl(120, 100%, 50%)").expect("hsl lime");
        assert_eq!((lime.r, lime.g, lime.b), (0, 255, 0), "hsl lime");
    }

    #[test]
    fn parse_canvas_color_hex_forms() {
        let c3 = parse_canvas_color("#f00").expect("#f00");
        assert_eq!((c3.r, c3.g, c3.b), (255, 0, 0), "#f00");

        let c6 = parse_canvas_color("#ff8000").expect("#ff8000");
        assert_eq!((c6.r, c6.g, c6.b), (255, 128, 0), "#ff8000");

        let c8 = parse_canvas_color("#ff000080").expect("#rrggbbaa");
        assert_eq!((c8.r, c8.a), (255, 128), "#rrggbbaa");
    }

    // -----------------------------------------------------------------------
    // Bug-fix tests for three DOM correctness issues
    // -----------------------------------------------------------------------

    /// Bug 1: EventTarget.dispatchEvent must stamp event.target and
    /// event.currentTarget before invoking listeners.
    #[test]
    fn dispatch_event_stamps_target_and_current_target() {
        let doc = cv_html::parse("<!doctype html><html><body></body></html>");
        let mut runtime = LiveInterp::new(&doc, "https://example.com/");

        // Standalone EventTarget object: dispatchEvent must set target and
        // currentTarget to the EventTarget instance before invoking listeners.
        runtime
            .interp
            .run(
                "var et = new EventTarget();\
                 var captured_target = null;\
                 var captured_ct = null;\
                 et.addEventListener('ping', function(ev) {\
                     captured_target = ev.target;\
                     captured_ct = ev.currentTarget;\
                 });\
                 et.dispatchEvent(new Event('ping'));\
                 window.__et_target_ok = (captured_target === et);\
                 window.__et_ct_ok = (captured_ct === et);",
            )
            .expect("EventTarget dispatchEvent run");

        assert_eq!(
            window_str(&runtime, "__et_target_ok"),
            "true",
            "EventTarget.dispatchEvent must set event.target to the EventTarget object"
        );
        assert_eq!(
            window_str(&runtime, "__et_ct_ok"),
            "true",
            "EventTarget.dispatchEvent must set event.currentTarget to the EventTarget object"
        );

        // createElement'd DOM element: dispatchEvent must also set target.
        runtime
            .interp
            .run(
                "var btn = document.createElement('button');\
                 document.body.appendChild(btn);\
                 var btn_target = null;\
                 btn.addEventListener('click', function(ev) { btn_target = ev.target; });\
                 btn.dispatchEvent(new Event('click'));\
                 window.__btn_target_ok = (btn_target === btn);",
            )
            .expect("createElement dispatchEvent target run");

        assert_eq!(
            window_str(&runtime, "__btn_target_ok"),
            "true",
            "element.dispatchEvent must set event.target to the element"
        );
    }

    /// Bug 2: insertBefore(node, null) must behave like appendChild (no throw);
    /// insertBefore(node, nonChildRef) must throw NotFoundError.
    #[test]
    fn insert_before_null_appends_and_non_child_throws() {
        let doc = cv_html::parse(
            "<!doctype html><html><body><div id='parent'><span id='a'>A</span></div></body></html>",
        );
        let mut runtime = LiveInterp::new(&doc, "https://example.com/");

        // insertBefore(node, null) must not throw and must return the new child.
        runtime
            .interp
            .run(
                "var parent = document.getElementById('parent');\
                 var nu = document.createElement('span');\
                 nu.id = 'nu';\
                 var returned = null;\
                 var threw_on_null = false;\
                 try { returned = parent.insertBefore(nu, null); }\
                 catch(e) { threw_on_null = true; }\
                 window.__ib_null_no_throw = !threw_on_null;\
                 window.__ib_null_returns_node = (returned === nu);",
            )
            .expect("insertBefore(node, null) run");

        assert_eq!(
            window_str(&runtime, "__ib_null_no_throw"),
            "true",
            "insertBefore(node, null) must not throw"
        );
        assert_eq!(
            window_str(&runtime, "__ib_null_returns_node"),
            "true",
            "insertBefore(node, null) must return the inserted node"
        );

        // insertBefore(node, nonChildRef) must throw NotFoundError.
        // parent is an SSR element from getElementById; unrelated is a
        // createElement'd element that is NOT a child of parent.
        runtime
            .interp
            .run(
                "var parent3 = document.getElementById('parent');\
                 var unrelated = document.createElement('div');\
                 var nodeToInsert = document.createElement('span');\
                 var threw_not_found = false;\
                 try {\
                     parent3.insertBefore(nodeToInsert, unrelated);\
                 } catch(e) {\
                     threw_not_found = (e && e.name === 'NotFoundError');\
                 }\
                 window.__ib_throws_ok = threw_not_found;",
            )
            .expect("insertBefore throws run");

        assert_eq!(
            window_str(&runtime, "__ib_throws_ok"),
            "true",
            "insertBefore(node, nonChildRef) must throw DOMException NotFoundError"
        );
    }

    /// Bug 3: removeChild must throw NotFoundError when the node is not a
    /// direct child of the parent.
    #[test]
    fn remove_child_throws_not_found_for_non_child() {
        let doc = cv_html::parse(
            "<!doctype html><html><body><div id='parent'><span id='a'>A</span></div>\
             <div id='other'><span id='b'>B</span></div></body></html>",
        );
        let mut runtime = LiveInterp::new(&doc, "https://example.com/");

        runtime
            .interp
            .run(
                "var parent = document.getElementById('parent');\
                 var b = document.getElementById('b');\
                 var threw_not_found = false;\
                 try {\
                     parent.removeChild(b);\
                 } catch(e) {\
                     threw_not_found = (e && e.name === 'NotFoundError');\
                 }\
                 window.__rc_throws_ok = threw_not_found;\
                 \
                 var a = document.getElementById('a');\
                 var threw_for_valid = false;\
                 try { parent.removeChild(a); } catch(e) { threw_for_valid = true; }\
                 window.__rc_valid_ok = !threw_for_valid;",
            )
            .expect("removeChild throws run");

        assert_eq!(
            window_str(&runtime, "__rc_throws_ok"),
            "true",
            "removeChild(nonChild) must throw DOMException NotFoundError"
        );
        assert_eq!(
            window_str(&runtime, "__rc_valid_ok"),
            "true",
            "removeChild(directChild) must succeed without throwing"
        );
    }

    // Bug 1: getAttribute returns null for empty-string attribute values.
    // Per spec, getAttribute("disabled") on <input disabled> (or after
    // setAttribute("disabled", "")) must return "" not null.
    #[test]
    fn get_attribute_returns_empty_string_for_valueless_attribute() {
        // Case A: element created via createElement + setAttribute("disabled", "")
        let doc = cv_html::parse("<!doctype html><html><body></body></html>");
        let mut runtime = LiveInterp::new(&doc, "https://example.com/");
        runtime
            .interp
            .run(
                "var el = document.createElement('input'); \
                 el.setAttribute('disabled', ''); \
                 var v = el.getAttribute('disabled'); \
                 window.__ga_ce = (v === '') ? 'empty_string' : (v === null ? 'null' : 'other:' + v);",
            )
            .expect("createElement getAttribute run");
        // Note: run() returns Undefined for scripts without 'return', so read back from window.
        assert_eq!(
            window_str(&runtime, "__ga_ce"),
            "empty_string",
            "createElement + setAttribute('disabled','') must return '' not null"
        );

        // Case B: existing element from HTML parser — <input disabled> has valueless attr.
        // Store the result in a global so we can read it back (run() always returns Undefined
        // for non-return scripts).
        let html = "<!doctype html><html><body><input id='inp' disabled><script>\
            var inp = document.getElementById('inp');\
            window.__ga_inp = inp ? inp.getAttribute('disabled') : '__no_el';\
            </script></body></html>";
        let cfg = cv_layout::LayoutConfig::default();
        let (runtime2, _doc2, _sheets2, _paint2) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");
        let s = window_str(&runtime2, "__ga_inp");
        assert!(
            s == "",
            "existing <input disabled> getAttribute('disabled') must return '' not null, got {:?}",
            s
        );
    }

    // Bug 2: createElementNS / setAttribute must preserve SVG attribute case.
    // viewBox, gradientTransform, etc. are case-sensitive in SVG.
    #[test]
    fn create_element_ns_svg_preserves_attribute_case() {
        let doc = cv_html::parse("<!doctype html><html><body></body></html>");
        let mut runtime = LiveInterp::new(&doc, "https://example.com/");
        runtime
            .interp
            .run(
                "var svgNS = 'http://www.w3.org/2000/svg'; \
                 var fe = document.createElementNS(svgNS, 'feGaussianBlur'); \
                 window.__svg_tag = fe.tagName; \
                 var svg = document.createElementNS(svgNS, 'svg'); \
                 svg.setAttribute('viewBox', '0 0 100 100'); \
                 window.__svg_vb = svg.getAttribute('viewBox'); \
                 var grad = document.createElementNS(svgNS, 'linearGradient'); \
                 grad.setAttribute('gradientTransform', 'rotate(45)'); \
                 window.__svg_gt = grad.getAttribute('gradientTransform'); \
                 var svgClone = svg.cloneNode(false); \
                 svgClone.setAttribute('viewBox', '0 0 50 50'); \
                 window.__svg_clone_vb = svgClone.getAttribute('viewBox');",
            )
            .expect("SVG attribute case run");

        assert_eq!(
            window_str(&runtime, "__svg_tag"),
            "feGaussianBlur",
            "createElementNS tagName must preserve feGaussianBlur case"
        );
        assert_eq!(
            window_str(&runtime, "__svg_vb"),
            "0 0 100 100",
            "getAttribute('viewBox') must return exact-case match"
        );
        assert_eq!(
            window_str(&runtime, "__svg_gt"),
            "rotate(45)",
            "getAttribute('gradientTransform') must return value set with case-sensitive key"
        );
        assert_eq!(
            window_str(&runtime, "__svg_clone_vb"),
            "0 0 50 50",
            "cloneNode must propagate _isSvg so setAttribute on clone preserves attribute case"
        );
    }

    // Bug 3: inline onclick must not discard the element href.
    // <a href="/page" onclick="track()"> must navigate to /page after running track().
    // The link_href must encode BOTH the onclick JS and the navigation target.
    #[test]
    fn onclick_attribute_does_not_overwrite_href() {
        let html = "<!doctype html><html><body>\
            <a id='lnk' href='/target-page' onclick='window.__onclick_ran=1'>click me</a>\
            </body></html>";
        let cfg = cv_layout::LayoutConfig::default();
        let (_runtime, _doc, _sheets, paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, "")
                .expect("render ok");

        // Find the hit_region for the link — its href must encode BOTH
        // the onclick JS source AND the navigation href (|||nav:/target-page).
        let link_region = paint
            .hit_regions
            .iter()
            .find(|r| r.href.as_deref().map(|h| h.contains("onclick_ran") || h.contains("target-page")).unwrap_or(false));

        let href_val = link_region
            .and_then(|r| r.href.as_deref())
            .unwrap_or("");

        // The href must start with "javascript:" (onclick runs first)
        // AND must contain the nav:/target-page suffix so navigation happens too.
        assert!(
            href_val.starts_with("javascript:"),
            "onclick element must encode JS handler in href, got {:?}",
            href_val
        );
        assert!(
            href_val.contains("nav:/target-page"),
            "onclick element href must preserve navigation target via |||nav: suffix, got {:?}",
            href_val
        );
    }

    // ── Bug 2: KeyboardEvent.code must be the physical key, not a copy of key ──
    // The internal dispatch path (dispatch_keyboard_event → key_to_code) is
    // verified by key_to_code_maps_letters_digits_and_specials (pure unit test).
    // This integration test confirms that when a keydown event with explicit
    // key/code fields is dispatched via an element's dispatchEvent, the handler
    // receives the correct values (not a copy of key in code).
    #[test]
    fn keyboard_event_code_is_physical_not_logical() {
        // Dispatch via an element's dispatchEvent (not document.dispatchEvent)
        // and store results on window so extra_js can read them.
        let html = r#"<!doctype html><html><body>
<div id="el"></div>
<script>
window.kbResults = [];
document.getElementById('el').addEventListener('keydown', function(e) {
    window.kbResults.push(e.key + ':' + e.code);
});
</script>
</body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        let extra = r#"
            var el = document.getElementById('el');
            el.dispatchEvent({type:'keydown', bubbles:false, key:'a',         code:'KeyA'});
            el.dispatchEvent({type:'keydown', bubbles:false, key:' ',         code:'Space'});
            el.dispatchEvent({type:'keydown', bubbles:false, key:'1',         code:'Digit1'});
            el.dispatchEvent({type:'keydown', bubbles:false, key:'ArrowLeft', code:'ArrowLeft'});
            document.title = window.kbResults.join('|');
        "#;
        let (runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        let title = runtime.title_override().unwrap_or_default();
        assert!(
            title.contains("a:KeyA"),
            "letter 'a' must produce code 'KeyA', got title: {title:?}"
        );
        assert!(
            title.contains(" :Space"),
            "space must produce code 'Space', got title: {title:?}"
        );
        assert!(
            title.contains("1:Digit1"),
            "digit '1' must produce code 'Digit1', got title: {title:?}"
        );
        assert!(
            title.contains("ArrowLeft:ArrowLeft"),
            "ArrowLeft must produce code 'ArrowLeft', got title: {title:?}"
        );
    }

    // Internal key_to_code unit tests — verify the mapping is correct without
    // needing a full browser render.
    #[test]
    fn key_to_code_maps_letters_digits_and_specials() {
        assert_eq!(key_to_code("a"), "KeyA");
        assert_eq!(key_to_code("A"), "KeyA");
        assert_eq!(key_to_code("z"), "KeyZ");
        assert_eq!(key_to_code("1"), "Digit1");
        assert_eq!(key_to_code("9"), "Digit9");
        assert_eq!(key_to_code(" "), "Space");
        assert_eq!(key_to_code("Enter"), "Enter");
        assert_eq!(key_to_code("Escape"), "Escape");
        assert_eq!(key_to_code("Backspace"), "Backspace");
        assert_eq!(key_to_code("Tab"), "Tab");
        assert_eq!(key_to_code("Delete"), "Delete");
        assert_eq!(key_to_code("ArrowLeft"), "ArrowLeft");
        assert_eq!(key_to_code("ArrowRight"), "ArrowRight");
        assert_eq!(key_to_code("ArrowUp"), "ArrowUp");
        assert_eq!(key_to_code("ArrowDown"), "ArrowDown");
        assert_eq!(key_to_code("Home"), "Home");
        assert_eq!(key_to_code("End"), "End");
        assert_eq!(key_to_code("PageUp"), "PageUp");
        assert_eq!(key_to_code("PageDown"), "PageDown");
        assert_eq!(key_to_code("F1"), "F1");
        assert_eq!(key_to_code("F12"), "F12");
        assert_eq!(key_to_code(";"), "Semicolon");
        assert_eq!(key_to_code(":"), "Semicolon");
        assert_eq!(key_to_code("="), "Equal");
        assert_eq!(key_to_code(","), "Comma");
        assert_eq!(key_to_code("-"), "Minus");
        assert_eq!(key_to_code("."), "Period");
        assert_eq!(key_to_code("/"), "Slash");
        assert_eq!(key_to_code("["), "BracketLeft");
        assert_eq!(key_to_code("]"), "BracketRight");
    }

    // ── Bug 1: event.bubbles is honoured by dispatch_event_to_path ──
    #[test]
    fn non_bubbling_event_does_not_reach_ancestor() {
        // Focus events have bubbles:false. An ancestor addEventListener for
        // "focus" must NOT be called when a child fires a non-bubbling focus.
        // Use a plain object with `bubbles:false` (no FocusEvent constructor
        // needed) to trigger dispatch_event_to_path's bubble-guard.
        // Counters stored on `window` so they're accessible from extra_js.
        let html = r#"<!doctype html><html><body>
<div id="parent"><input id="child" /></div>
<script>
window.parentHits = 0;
window.childHits  = 0;
document.getElementById('parent').addEventListener('focus', function(){ window.parentHits++; });
document.getElementById('child').addEventListener('focus',  function(){ window.childHits++;  });
</script>
</body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        let extra = r#"
            // Dispatch a non-bubbling focus event on the child.
            var child = document.getElementById('child');
            child.dispatchEvent({type:'focus', bubbles:false});
            document.title = 'child=' + window.childHits + ',parent=' + window.parentHits;
        "#;
        let (runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        let title = runtime.title_override().unwrap_or_default();
        assert!(
            title.contains("child=1"),
            "child focus listener must fire once, got title: {title:?}"
        );
        assert!(
            title.contains("parent=0"),
            "ancestor must NOT receive non-bubbling focus, got title: {title:?}"
        );
    }

    // ── Bug 3: element.dataset is a live DOMStringMap ──
    #[test]
    fn dataset_write_updates_get_attribute() {
        // Writing to dataset must be observable via getAttribute.
        let html = r#"<!doctype html><html><body>
<div id="el" data-initial="yes"></div>
<script>
var el = document.getElementById('el');
</script>
</body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        let extra = r#"
            var el = document.getElementById('el');
            // Read from HTML attribute.
            var init = el.dataset.initial;   // → "yes"
            // Write via dataset.
            el.dataset.newKey = 'hello';
            // Read back via getAttribute.
            var via_get = el.getAttribute('data-new-key');
            // Write via setAttribute and read back via dataset.
            el.setAttribute('data-another', 'world');
            var via_ds = el.dataset.another;
            document.title = init + '|' + via_get + '|' + via_ds;
        "#;
        let (runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        let title = runtime.title_override().unwrap_or_default();
        assert_eq!(
            title, "yes|hello|world",
            "dataset must be live: read HTML, write→getAttribute, setAttribute→dataset. Got: {title:?}"
        );
    }

