    // ── Bug 1: DOMParser.parseFromString returns queryable document ──────
    #[test]
    fn domparser_parse_from_string_querySelector_works() {
        let html = r#"<!doctype html><html><body></body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        let extra = r#"
            var parser = new DOMParser();
            var frag = parser.parseFromString(
                '<div id="main"><p class="intro">hello</p><span>world</span></div>',
                'text/html'
            );
            var byId   = frag.getElementById('main');
            var byQs   = frag.querySelector('p.intro');
            var byQsA  = frag.querySelectorAll('span');
            var byTag  = frag.getElementsByTagName('p');
            var byCls  = frag.getElementsByClassName('intro');
            var results = [
                byId   ? byId.id   : 'null',
                byQs   ? byQs.className : 'null',
                byQsA.length,
                byTag.length,
                byCls.length
            ].join('|');
            document.title = results;
        "#;
        let (runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        let title = runtime.title_override().unwrap_or_default();
        assert_eq!(
            title, "main|intro|1|1|1",
            "DOMParser.parseFromString must return a queryable document. Got: {title:?}"
        );
    }

    // ── Bug 2: indexedDB.open onsuccess/onupgradeneeded callbacks fire ────
    #[test]
    fn indexeddb_open_fires_onupgradeneeded_then_onsuccess() {
        let html = r#"<!doctype html><html><body></body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        // Use a unique DB name to avoid thread-local state from other tests.
        let extra = r#"
            window.__idbLog = [];
            var req = indexedDB.open('test_db_open_callbacks', 1);
            req.onupgradeneeded = function(e) {
                window.__idbLog.push('upgrade');
                var db = e.target.result;
                db.createObjectStore('items');
            };
            req.onsuccess = function(e) {
                window.__idbLog.push('success');
                window.__idbDb = e.target.result;
            };
        "#;
        let (mut runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        // Drain microtasks so the IDB callbacks fire.
        runtime.drain_due(100);
        let title_js = r#"document.title = window.__idbLog.join(',');"#;
        let _ = runtime.interp.run(title_js);
        let title = runtime.title_override().unwrap_or_default();
        assert_eq!(
            title, "upgrade,success",
            "indexedDB.open must fire onupgradeneeded then onsuccess. Got: {title:?}"
        );
    }

    #[test]
    fn indexeddb_put_and_get_fire_onsuccess() {
        let html = r#"<!doctype html><html><body></body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        let extra = r#"
            window.__idbGot = null;
            var req = indexedDB.open('test_db_put_get', 1);
            req.onupgradeneeded = function(e) {
                e.target.result.createObjectStore('kv');
            };
            req.onsuccess = function(e) {
                var db = e.target.result;
                var tx  = db.transaction('kv', 'readwrite');
                var store = tx.objectStore('kv');
                var putReq = store.put('hello_world', 'mykey');
                putReq.onsuccess = function() {
                    var getReq = store.get('mykey');
                    getReq.onsuccess = function(ev) {
                        window.__idbGot = ev.target.result;
                    };
                };
            };
        "#;
        let (mut runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        // Multiple drain rounds: open → upgrade → success → put → get.
        runtime.drain_due(500);
        let title_js = r#"document.title = String(window.__idbGot);"#;
        let _ = runtime.interp.run(title_js);
        let title = runtime.title_override().unwrap_or_default();
        assert_eq!(
            title, "hello_world",
            "IDB put then get must deliver the value via onsuccess. Got: {title:?}"
        );
    }

