    // Isolate the NESTING: update() is defined inside animate(), which is invoked
    // from a callback — and update captures several outer locals (the exact
    // hyvechain shape). Driven through native rAF.
    #[test]
    fn raf_nested_closure_self_rearm_runs_many_frames() {
        let html = r#"<!doctype html><html><body></body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        let extra = r#"
            window.__c = 0; window.__err = '';
            function animate(target){
              var i = 0;
              var startTime = performance.now();
              var fmt = function(n){ return Math.floor(n); };
              var update = function(now){
                try {
                  i = i + 1; window.__c = i;
                  var elapsed = now - startTime;
                  fmt(elapsed);
                  if (i < 20) { requestAnimationFrame(update); }
                } catch(e){ window.__err = String(e); }
              };
              requestAnimationFrame(update);
            }
            (function(cb){ cb(7847); })(function(t){ animate(t); });
        "#;
        let (mut runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        for _ in 0..60 {
            runtime.drain_due(200);
            std::thread::sleep(std::time::Duration::from_millis(2));
        }
        let _ = runtime.interp.run("document.title = String(window.__c) + ' err=' + window.__err;");
        let title = runtime.title_override().unwrap_or_default();
        assert_eq!(title, "20 err=", "nested self-re-arming rAF closure must run all 20 frames, got {title:?}");
    }

    // ── hyvechain stat count-up (IntersectionObserver + rAF + performance.now) ──
    // Reproduces the hyvechain.com hero-stat "0/0/0" bug end-to-end: a
    // `[data-count]` span whose value is driven by an IntersectionObserver that,
    // on first intersection, runs a `requestAnimationFrame` count-up reading
    // `performance.now()`. We build the real runtime, fire the observer step
    // (as the live ticker does), then drive frames with an ADVANCING clock and
    // assert the span reaches its target. Frames advance real wall-clock time
    // (a tiny sleep) so `performance.now()` progresses exactly as it does in the
    // 16ms window ticker — if the engine froze the rAF clock during a drain
    // burst, this catches it.
    #[test]
    fn hyvechain_stat_count_up_reaches_target() {
        let html = r#"<!doctype html><html><body>
            <span class="stat-value" data-count="7847">7,847</span>
        </body></html>"#;
        let cfg = cv_layout::LayoutConfig {
            viewport_w: 1280.0,
            viewport_h: 800.0,
            measure_text_fn: Some(layout_text_measurer()),
            ..cv_layout::LayoutConfig::default()
        };
        // The exact hyvechain count-up pattern (the `initCounters` path).
        let extra = r#"
            (function(){
              var counters = document.querySelectorAll('[data-count]');
              var animate = function(counter){
                var raw = counter.getAttribute('data-count');
                var target = parseFloat(raw);
                var decimals = raw.indexOf('.') >= 0 ? raw.split('.')[1].length : 0;
                var duration = 2000;
                var startTime = performance.now();
                var fmt = function(n){ return decimals > 0 ? n.toFixed(decimals) : Math.floor(n).toLocaleString(); };
                var update = function(now){
                  var elapsed = now - startTime;
                  var progress = Math.min(elapsed / duration, 1);
                  var eased = 1 - Math.pow(1 - progress, 4);
                  counter.textContent = fmt(eased * target);
                  if (progress < 1) { requestAnimationFrame(update); }
                  else { counter.textContent = fmt(target); }
                };
                requestAnimationFrame(update);
              };
              var observer = new IntersectionObserver(function(entries){
                entries.forEach(function(entry){
                  if (entry.isIntersecting){ animate(entry.target); observer.unobserve(entry.target); }
                });
              }, { threshold: 0.5 });
              counters.forEach(function(c){ observer.observe(c); });
            })();
        "#;
        let (mut runtime, _doc, _sheets, paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        let layout_root = paint.layout_root.clone().expect("layout root");
        // Drive ~3 seconds of frames at the live 16ms cadence. Each frame: run the
        // observer step (fires the IO once → starts the rAF count-up) then drain
        // the event loop (advances exactly one rAF generation per call).
        // Drive ~3.2s of frames at the live 16ms cadence. Each frame: run the
        // observer step (fires the IO once → starts the rAF count-up) then drain
        // the event loop (advances exactly one rAF generation per call).
        for _ in 0..200 {
            maybe_run_observers(
                &mut runtime,
                &layout_root,
                (1280.0, 800.0),
                0.0,
                process_now_ms() as f32,
            );
            runtime.drain_due(200);
            std::thread::sleep(std::time::Duration::from_millis(16));
        }
        let _ = runtime.interp.run(
            "document.title = document.querySelector('.stat-value').textContent;",
        );
        let title = runtime.title_override().unwrap_or_default();
        assert_eq!(
            title, "7,847",
            "hyvechain count-up must reach its data-count target, got {title:?}"
        );
    }

    // The page's SECOND counter path: `initCounterScramble` / `scrambleToNumber`.
    // VERBATIM from hyvechain.com/js/main.js — a named `function update()` (not a
    // var) that re-arms via requestAnimationFrame(update), scrambles random digits
    // for 60% of the duration then eases to the target. This is what actually
    // paints the hero "0/0/0" if it stalls. Driven exactly like the live ticker.
    #[test]
    fn hyvechain_scramble_counter_reaches_target() {
        let html = r#"<!doctype html><html><body>
            <span class="stat-value counter-scramble" data-count="7847">7,847</span>
        </body></html>"#;
        let cfg = cv_layout::LayoutConfig {
            viewport_w: 1280.0,
            viewport_h: 800.0,
            measure_text_fn: Some(layout_text_measurer()),
            ..cv_layout::LayoutConfig::default()
        };
        // Verbatim structure of initCounterScramble + scrambleToNumber.
        let extra = r#"
            function scrambleToNumber(el, target, duration, decimals) {
                decimals = decimals || 0;
                var startTime = performance.now();
                var chars = '0123456789';
                var formatTarget = function(n){ return decimals > 0 ? n.toFixed(decimals) : Math.floor(n).toLocaleString(); };
                var formatted = formatTarget(target);
                var scramblePhase = duration * 0.6;
                el.classList.add('counter-scramble');
                function update(currentTime) {
                    var elapsed = currentTime - startTime;
                    var progress = Math.min(elapsed / duration, 1);
                    if (progress < 1) {
                        if (elapsed < scramblePhase) {
                            var accuracy = elapsed / scramblePhase;
                            var result = '';
                            for (var i = 0; i < formatted.length; i++) {
                                if (formatted[i] === ',' || formatted[i] === '.') { result += formatted[i]; }
                                else if (Math.random() < accuracy * 0.8) { result += formatted[i]; }
                                else { result += chars[Math.floor(Math.random() * chars.length)]; }
                            }
                            el.textContent = result;
                        } else {
                            var countProgress = (elapsed - scramblePhase) / (duration - scramblePhase);
                            var eased = 1 - Math.pow(1 - countProgress, 3);
                            el.textContent = formatTarget(eased * target);
                        }
                        requestAnimationFrame(update);
                    } else {
                        el.textContent = formatted;
                    }
                }
                requestAnimationFrame(update);
            }
            (function initCounterScramble(){
                var counters = document.querySelectorAll('[data-count]');
                if (counters.length === 0) return;
                var scrambleObserver = new IntersectionObserver(function(entries){
                    entries.forEach(function(entry){
                        if (entry.isIntersecting) {
                            var el = entry.target;
                            var raw = el.getAttribute('data-count');
                            var target = parseFloat(raw);
                            var decimals = raw.indexOf('.') >= 0 ? raw.split('.')[1].length : 0;
                            scrambleToNumber(el, target, 2000, decimals);
                            scrambleObserver.unobserve(el);
                        }
                    });
                }, { threshold: 0.5 });
                counters.forEach(function(counter){ scrambleObserver.observe(counter); });
            })();
        "#;
        let (mut runtime, _doc, _sheets, paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        let layout_root = paint.layout_root.clone().expect("layout root");
        for _ in 0..200 {
            maybe_run_observers(
                &mut runtime,
                &layout_root,
                (1280.0, 800.0),
                0.0,
                process_now_ms() as f32,
            );
            runtime.drain_due(200);
            std::thread::sleep(std::time::Duration::from_millis(16));
        }
        let _ = runtime.interp.run(
            "document.title = document.querySelector('.stat-value').textContent;",
        );
        let title = runtime.title_override().unwrap_or_default();
        assert_eq!(
            title, "7,847",
            "hyvechain scramble counter must reach target, got {title:?}"
        );
    }

