    // ── M6.2: IndexedDB durability (persist to disk + reload on open) ─────────
    //
    // A unique temp DIRECTORY for one durability test. Never touches the real
    // %APPDATA%\Conclave\indexeddb. Uses pid + an atomic counter so parallel
    // test threads never collide.
    fn temp_idb_dir(tag: &str) -> std::path::PathBuf {
        use std::sync::atomic::{AtomicU64, Ordering};
        static N: AtomicU64 = AtomicU64::new(0);
        let n = N.fetch_add(1, Ordering::Relaxed);
        let mut p = std::env::temp_dir();
        p.push(format!(
            "tb_idb_e2e_{}_{}_{}",
            tag,
            std::process::id(),
            n
        ));
        let _ = std::fs::remove_dir_all(&p);
        p
    }

    /// Run `extra_js` in a FRESH thread (so the IndexedDB `REG` thread-local is
    /// empty — a true cold start) with the IndexedDB persistence directory
    /// pointed at `dir`, then drain microtasks and return `document.title`.
    /// This is the in-process stand-in for a process restart: two calls with
    /// the same `dir` see the first call's writes via disk, not via shared
    /// in-memory state.
    fn run_idb_in_fresh_process(dir: &std::path::Path, extra_js: &str) -> String {
        let dir = dir.to_path_buf();
        let extra_js = extra_js.to_string();
        std::thread::spawn(move || {
            crate::idb_persist::set_dir_for_test(Some(dir));
            let html = r#"<!doctype html><html><body></body></html>"#;
            let cfg = cv_layout::LayoutConfig::default();
            let (mut runtime, _doc, _sheets, _paint) =
                build_runtime_and_first_paint(html, "https://example.com/", &cfg, &extra_js)
                    .expect("render ok");
            // Generous drain: open → upgrade → success → writes → reads.
            runtime.drain_due(2000);
            let title = runtime.title_override().unwrap_or_default();
            crate::idb_persist::set_dir_for_test(None);
            title
        })
        .join()
        .expect("idb test thread panicked")
    }

    #[test]
    fn indexeddb_restart_oracle_data_survives_reload() {
        let dir = temp_idb_dir("restart");

        // ── "Run 1": create the schema and write rows, then close. The flush
        // hook persists everything to disk under `dir`.
        let write_js = r#"
            var req = indexedDB.open('oracle_db', 1);
            req.onupgradeneeded = function(e) {
                var db = e.target.result;
                var s = db.createObjectStore('people', { keyPath: 'id', autoIncrement: true });
            };
            req.onsuccess = function(e) {
                var db = e.target.result;
                var tx = db.transaction('people', 'readwrite');
                var store = tx.objectStore('people');
                // keyPath 'id': the numeric key is extracted from value.id, so
                // the reloaded key must stay Number(1), never String("1").
                store.add({ id: 1, name: 'Alice', tags: ['a','b'], meta: { score: 9.5, ok: true, note: null } });
                store.add({ id: 2, name: 'Bob',   tags: [] });
                store.add({ id: 3, name: 'Cara',  tags: ['x'] });
                document.title = 'wrote';
            };
        "#;
        let t1 = run_idb_in_fresh_process(&dir, write_js);
        assert_eq!(t1, "wrote", "write run should complete");

        // ── "Run 2": a cold process (fresh thread ⇒ empty REG) opens the same
        // DB. It must reload from disk: same count, getAll, typed keys, nested
        // values — without any onupgradeneeded re-running (schema already there).
        let read_js = r#"
            window.__out = 'PENDING';
            var req = indexedDB.open('oracle_db', 1);
            var upgraded = false;
            req.onupgradeneeded = function(e) { upgraded = true; };
            req.onsuccess = function(e) {
                var db = e.target.result;
                var tx = db.transaction('people', 'readwrite');
                var store = tx.objectStore('people');
                var cReq = store.count();
                cReq.onsuccess = function(cv) {
                    var count = cv.target.result;
                    var gReq = store.get(1);
                    gReq.onsuccess = function(gv) {
                        var rec = gv.target.result;
                        // get(1) must return Alice's record (numeric key 1, not "1").
                        var name = rec ? rec.name : 'MISSING';
                        var score = (rec && rec.meta) ? rec.meta.score : 'NOSCORE';
                        var firstTag = (rec && rec.tags && rec.tags.length) ? rec.tags[0] : 'NOTAG';
                        var noteIsNull = (rec && rec.meta && rec.meta.note === null) ? 'nullok' : 'notnull';
                        window.__out = [
                            'count=' + count,
                            'name=' + name,
                            'score=' + score,
                            'tag=' + firstTag,
                            noteIsNull,
                            'upgraded=' + upgraded
                        ].join('|');
                    };
                };
            };
            window.__finalize = function() { document.title = String(window.__out); };
        "#;
        let report = run_idb_read_and_finalize(&dir, read_js);

        assert_eq!(
            report,
            "count=3|name=Alice|score=9.5|tag=a|nullok|upgraded=false",
            "restart oracle: reopened DB must serve identical data with typed \
             keys/nested values and NO re-upgrade. Got: {report:?}"
        );

        let _ = std::fs::remove_dir_all(&dir);
    }

    /// Like [`run_idb_in_fresh_process`] but drains, then calls the page's
    /// `__finalize()` (which copies `window.__out` into `document.title`) so the
    /// async callback result is observable after the microtask chain settles.
    fn run_idb_read_and_finalize(dir: &std::path::Path, extra_js: &str) -> String {
        let dir = dir.to_path_buf();
        let extra_js = extra_js.to_string();
        std::thread::spawn(move || {
            crate::idb_persist::set_dir_for_test(Some(dir));
            let html = r#"<!doctype html><html><body></body></html>"#;
            let cfg = cv_layout::LayoutConfig::default();
            let (mut runtime, _doc, _sheets, _paint) =
                build_runtime_and_first_paint(html, "https://example.com/", &cfg, &extra_js)
                    .expect("render ok");
            runtime.drain_due(2000);
            let _ = runtime.interp.run("window.__finalize && window.__finalize();");
            let title = runtime.title_override().unwrap_or_default();
            crate::idb_persist::set_dir_for_test(None);
            title
        })
        .join()
        .expect("idb read thread panicked")
    }

    #[test]
    fn indexeddb_autoincrement_counter_survives_restart() {
        let dir = temp_idb_dir("autoinc");

        // Run 1: two adds ⇒ keys 1,2; next counter is 3.
        let write_js = r#"
            var req = indexedDB.open('counter_db', 1);
            req.onupgradeneeded = function(e) {
                e.target.result.createObjectStore('log', { autoIncrement: true });
            };
            req.onsuccess = function(e) {
                var db = e.target.result;
                var store = db.transaction('log','readwrite').objectStore('log');
                store.add('first');
                store.add('second');
                document.title = 'wrote';
            };
        "#;
        assert_eq!(run_idb_in_fresh_process(&dir, write_js), "wrote");

        // Run 2: cold reopen; the next add() must continue the sequence at 3,
        // NOT restart at 1 (which would collide with the reloaded key 1).
        let read_js = r#"
            window.__out = 'PENDING';
            var req = indexedDB.open('counter_db', 1);
            req.onsuccess = function(e) {
                var db = e.target.result;
                var store = db.transaction('log','readwrite').objectStore('log');
                var addReq = store.add('third');
                addReq.onsuccess = function(av) {
                    var assignedKey = av.target.result; // should be 3
                    var cReq = store.count();
                    cReq.onsuccess = function(cv) {
                        window.__out = 'key=' + assignedKey + '|count=' + cv.target.result;
                    };
                };
            };
            window.__finalize = function() { document.title = String(window.__out); };
        "#;
        let report = run_idb_read_and_finalize(&dir, read_js);
        assert_eq!(
            report, "key=3|count=3",
            "autoIncrement counter must resume at 3 after restart (1,2 persisted). Got: {report:?}"
        );

        let _ = std::fs::remove_dir_all(&dir);
    }

    #[test]
    fn indexeddb_fresh_db_with_no_file_behaves_as_today() {
        // A brand-new DB with no on-disk file must behave exactly as the
        // in-memory backend always has: onupgradeneeded fires, put/get works.
        let dir = temp_idb_dir("fresh");
        let js = r#"
            window.__out = 'PENDING';
            window.__log = [];
            var req = indexedDB.open('brand_new_db', 1);
            req.onupgradeneeded = function(e) {
                window.__log.push('upgrade');
                e.target.result.createObjectStore('kv');
            };
            req.onsuccess = function(e) {
                window.__log.push('success');
                var db = e.target.result;
                var store = db.transaction('kv','readwrite').objectStore('kv');
                var pReq = store.put('val', 'k');
                pReq.onsuccess = function() {
                    var gReq = store.get('k');
                    gReq.onsuccess = function(gv) {
                        window.__out = window.__log.join(',') + '|' + gv.target.result;
                    };
                };
            };
            window.__finalize = function() { document.title = String(window.__out); };
        "#;
        let report = run_idb_read_and_finalize(&dir, js);
        assert_eq!(
            report, "upgrade,success|val",
            "fresh DB (no file): onupgradeneeded fires, put/get works. Got: {report:?}"
        );
        let _ = std::fs::remove_dir_all(&dir);
    }

    #[test]
    fn indexeddb_corrupt_file_treated_as_empty_db_no_panic() {
        // A corrupt/garbage file for a DB must be treated as an empty database:
        // the open succeeds, onupgradeneeded fires (it looks brand-new), and no
        // panic occurs.
        let dir = temp_idb_dir("corrupt");
        std::fs::create_dir_all(&dir).unwrap();
        // Write a garbage .idb file using the SAME filename hashing the loader
        // uses, so the loader actually reads it. We can't call the private
        // db_filename, so just drop several garbage .idb files; the loader scans
        // by hashed name for THIS db, and `databases()` scans all .idb files.
        // The targeted file: replicate the hash via a fixed corrupt blob written
        // by the persistence layer is not exposed, so instead corrupt by writing
        // every plausible candidate — simplest: write one obviously-bad file and
        // rely on from_bytes() rejecting it for the targeted db (load_snapshot
        // returns None ⇒ empty DB). We exercise from_bytes directly too.
        assert!(crate::idb_persist::DbSnapshot::from_bytes(b"\x00\x01garbage").is_none());

        // End-to-end: a DB whose (hashed) file we corrupt must open as empty.
        // Write the corrupt bytes through a first run that we then clobber.
        let seed_js = r#"
            var req = indexedDB.open('corrupt_db', 1);
            req.onupgradeneeded = function(e) { e.target.result.createObjectStore('s'); };
            req.onsuccess = function(e) {
                var st = e.target.result.transaction('s','readwrite').objectStore('s');
                st.put('shouldvanish', 'k');
                document.title = 'seeded';
            };
        "#;
        assert_eq!(run_idb_in_fresh_process(&dir, seed_js), "seeded");
        // Corrupt every .idb file in the dir (truncate to garbage).
        for entry in std::fs::read_dir(&dir).unwrap().flatten() {
            let p = entry.path();
            if p.extension().and_then(|e| e.to_str()) == Some("idb") {
                std::fs::write(&p, b"TBIDBcorrupt-not-a-valid-payload").unwrap();
            }
        }
        // Cold reopen: corrupt file ⇒ empty DB ⇒ onupgradeneeded fires again,
        // the old row is gone, no panic.
        let reopen_js = r#"
            window.__out = 'PENDING';
            var upgraded = false;
            var req = indexedDB.open('corrupt_db', 1);
            req.onupgradeneeded = function(e) { upgraded = true; e.target.result.createObjectStore('s'); };
            req.onsuccess = function(e) {
                var st = e.target.result.transaction('s','readwrite').objectStore('s');
                var g = st.get('k');
                g.onsuccess = function(gv) {
                    window.__out = 'upgraded=' + upgraded + '|val=' + String(gv.target.result);
                };
            };
            window.__finalize = function() { document.title = String(window.__out); };
        "#;
        let report = run_idb_read_and_finalize(&dir, reopen_js);
        assert_eq!(
            report, "upgraded=true|val=undefined",
            "corrupt file must be treated as empty DB (re-upgrade, old data gone), no panic. Got: {report:?}"
        );
        let _ = std::fs::remove_dir_all(&dir);
    }

    // ── Intl Bug 2: Segmenter granularity word / correct indices ─────────────

    #[test]
    fn intl_segmenter_word_granularity_splits_correctly() {
        let html = r#"<!doctype html><html><body></body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        let extra = r#"
            var seg = new Intl.Segmenter('en', { granularity: 'word' });
            var segs = Array.from(seg.segment('Hello world!'));
            // Expected segments: ["Hello"(word), " "(non), "world"(word), "!"(non)]
            var result = segs.map(function(s) { return s.segment + ':' + s.isWordLike; }).join(',');
            document.title = result;
        "#;
        let (mut runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        runtime.drain_due(100);
        let title = runtime.title_override().unwrap_or_default();
        assert_eq!(
            title, "Hello:true, :false,world:true,!:false",
            "Intl.Segmenter word: must split into word/non-word runs with isWordLike. Got: {title:?}"
        );
    }

    #[test]
    fn intl_segmenter_word_index_is_char_offset() {
        let html = r#"<!doctype html><html><body></body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        let extra = r#"
            var seg = new Intl.Segmenter('en', { granularity: 'word' });
            var segs = Array.from(seg.segment('Hi!'));
            // "Hi" at 0, "!" at 2
            document.title = segs.map(function(s){ return s.index; }).join(',');
        "#;
        let (mut runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        runtime.drain_due(100);
        let title = runtime.title_override().unwrap_or_default();
        assert_eq!(
            title, "0,2",
            "Intl.Segmenter word: index must be char offset in original string. Got: {title:?}"
        );
    }

    // ── Intl Bug 3: Collator case-insensitive sort ────────────────────────────

    #[test]
    fn intl_collator_sorts_case_insensitive() {
        let html = r#"<!doctype html><html><body></body></html>"#;
        let cfg = cv_layout::LayoutConfig::default();
        let extra = r#"
            var cmp = new Intl.Collator().compare;
            var arr = ["B", "a", "C", "b"];
            arr.sort(cmp);
            document.title = arr.join(',');
        "#;
        let (mut runtime, _doc, _sheets, _paint) =
            build_runtime_and_first_paint(html, "https://example.com/", &cfg, extra)
                .expect("render ok");
        runtime.drain_due(100);
        let title = runtime.title_override().unwrap_or_default();
        // Case-insensitive: a/b/B/C → sorted ignoring case then tiebreaking
        assert!(
            title == "a,B,b,C" || title == "a,b,B,C",
            "Intl.Collator.compare must sort case-insensitively. Got: {title:?}"
        );
    }

