    // ---- Bug 1: U+00A0 NBSP must not be treated as collapsible whitespace ----

    #[test]
    fn nbsp_preserved_through_normalize_inline_text() {
        // normalize_inline_text must not strip or collapse U+00A0.
        let input = "Mr.\u{00A0}Smith";
        let out = normalize_inline_text(input);
        assert!(
            out.contains('\u{00A0}'),
            "NBSP should survive normalize_inline_text; got: {out:?}"
        );
    }

    #[test]
    fn nbsp_only_text_node_not_pruned_by_is_css_collapsible_whitespace() {
        // is_css_collapsible_whitespace must return false for U+00A0.
        assert!(
            !is_css_collapsible_whitespace('\u{00A0}'),
            "U+00A0 must NOT be CSS-collapsible whitespace"
        );
        // Ordinary ASCII spaces/tabs/newlines ARE collapsible.
        assert!(is_css_collapsible_whitespace(' '));
        assert!(is_css_collapsible_whitespace('\t'));
        assert!(is_css_collapsible_whitespace('\n'));
        assert!(is_css_collapsible_whitespace('\r'));
        assert!(is_css_collapsible_whitespace('\x0C'));
    }

    // font-weight:900 must reach the LayoutBox as a NUMERIC weight (not collapse
    // to bold/700), and inline text inside the heading must INHERIT it. Covers
    // the full cv_css→cv_layout→LayoutBox thread (hyvechain h1 Orbitron 900).
    #[test]
    fn font_weight_900_threads_to_layout_box_and_inherits() {
        // Recursively find the max font_weight_num over all boxes that carry the
        // given text (the heading text is on the inline/text child box).
        fn max_weight_for_text(b: &cv_layout::LayoutBox, needle: &str) -> Option<u16> {
            let mut best = None;
            if let cv_layout::BoxKind::Text(t) = &b.kind {
                if t.contains(needle) {
                    best = Some(b.font_weight_num);
                }
            }
            for c in &b.children {
                if let Some(w) = max_weight_for_text(c, needle) {
                    best = Some(best.map_or(w, |b: u16| b.max(w)));
                }
            }
            best
        }
        let html = r#"<!doctype html><html><head><style>
            h1 { font-weight: 900; }
        </style></head><body><h1>Heavy <span>Heading</span></h1></body></html>"#;
        let doc = cv_html::parse(html);
        let sheets = collect_stylesheets(&doc);
        let cfg = cv_layout::LayoutConfig {
            viewport_w: 1280.0,
            viewport_h: 800.0,
            measure_text_fn: Some(layout_text_measurer()),
            ..cv_layout::LayoutConfig::default()
        };
        let lb = build_layout_tree(&doc, &sheets, "file:///t", &cfg, &Default::default());
        // The direct heading text and the nested <span> text must BOTH be 900
        // (font-weight inherits), not collapsed to bold(700).
        assert_eq!(
            max_weight_for_text(&lb, "Heavy"),
            Some(900),
            "h1 direct text must carry numeric weight 900"
        );
        assert_eq!(
            max_weight_for_text(&lb, "Heading"),
            Some(900),
            "nested <span> text must INHERIT font-weight 900"
        );
    }

    // `font-weight: bolder` must resolve against the INHERITED weight (CSS Fonts
    // 4 §2.4), not a fixed 700: bolder inside a weight-600 parent → 900.
    // ORACLE for interest-rect (Chrome cull_rect.cc) culling: a culled bake must
    // be BYTE-IDENTICAL to the full bake for every row WITHIN the interest band,
    // and leave rows OUTSIDE the band unrastered (background). Proves the cull
    // never drops content that should paint in the visible region. MUTATION-
    // checked: a box just inside the band must still paint (non-vacuous).
    #[test]
    fn interest_rect_cull_matches_full_bake_within_band() {
        // A tall page: many stacked 100px divs so boxes span far below the band.
        let mut body = String::new();
        for i in 0..120 {
            let shade = 16 + (i % 8) * 20;
            body.push_str(&format!(
                "<div style=\"height:100px;background:rgb({shade},{shade},{shade})\">row{i}</div>"
            ));
        }
        let html = format!(
            "<!doctype html><html><head></head><body style=\"margin:0\">{body}</body></html>"
        );
        let doc = cv_html::parse(&html);
        let sheets = collect_stylesheets(&doc);
        let cfg = cv_layout::LayoutConfig {
            viewport_w: 400.0,
            viewport_h: 600.0,
            measure_text_fn: Some(layout_text_measurer()),
            ..cv_layout::LayoutConfig::default()
        };
        let lb = build_layout_tree(&doc, &sheets, "file:///t", &cfg, &Default::default());
        let doc_h = (lb.content.y + lb.content.h).max(cfg.viewport_h) as u32;
        let w = cfg.viewport_w as u32;
        // Band at scroll_y=0: [0, vh + EXPAND]. Use a SMALL expand for the test so
        // some rows fall outside (the 120*100=12000px page exceeds it).
        let band_top = 0.0f32;
        let band_bottom = 1500.0f32; // viewport(600) + 900 margin
        // Full bake (no band).
        let mut full = cv_gfx::Bitmap::new(w, doc_h);
        full.clear(cv_gfx::Color::WHITE);
        let mut ft: Vec<cv_ui::TextItem> = Vec::new();
        INTEREST_BAND_Y.with(|c| c.set(None));
        paint_box(&lb, &mut full, &mut ft);
        // Culled bake (band set).
        let mut culled = cv_gfx::Bitmap::new(w, doc_h);
        culled.clear(cv_gfx::Color::WHITE);
        let mut ct: Vec<cv_ui::TextItem> = Vec::new();
        INTEREST_BAND_Y.with(|c| c.set(Some((band_top, band_bottom))));
        paint_box(&lb, &mut culled, &mut ct);
        INTEREST_BAND_Y.with(|c| c.set(None));
        // Within the band: every pixel identical to the full bake.
        let bb_row = band_bottom as u32;
        let mut in_band_diffs = 0u64;
        for y in 0..=bb_row.min(doc_h - 1) {
            for x in 0..w {
                let idx = (y * w + x) as usize;
                if full.pixels[idx] != culled.pixels[idx] {
                    in_band_diffs += 1;
                }
            }
        }
        assert_eq!(in_band_diffs, 0, "culled bake must equal full bake within the interest band");
        // FAR below the band (beyond one max box height of overhang): the culled
        // bake leaves the canvas background — boxes wholly below the band are
        // skipped. (A box STRADDLING band_bottom legitimately paints its full
        // height, so allow 200px of overhang past band_bottom.)
        let far = bb_row + 200;
        let mut out_band_painted = 0u64;
        let mut full_painted_far = 0u64;
        for y in far..doc_h {
            for x in 0..w {
                let idx = (y * w + x) as usize;
                if culled.pixels[idx] != cv_gfx::Color::WHITE.to_bgra_u32() {
                    out_band_painted += 1;
                }
                if full.pixels[idx] != cv_gfx::Color::WHITE.to_bgra_u32() {
                    full_painted_far += 1;
                }
            }
        }
        assert_eq!(
            out_band_painted, 0,
            "culled bake must leave rows far below the band unrastered (background)"
        );
        // NON-VACUITY: the full bake DID paint far below the band, so culling
        // actually skipped real content (otherwise the test proves nothing).
        assert!(
            full_painted_far > 0,
            "full bake must paint far below the band (else the cull test is vacuous)"
        );
    }

    // A `max-width` + `margin: 0 auto` container centers in a wide viewport even
    // when a SECOND rule adds `width: 100%` (the hyvechain `.hero-container`
    // idiom). CSS 2.2 §10.3.3: explicit width + both margins auto → centered.
    // Repro of the "content off to the left" bug on ultrawide displays.
    #[test]
    fn max_width_margin_auto_centers_with_width_100pct() {
        fn find_div_with_maxwidth(
            b: &cv_layout::LayoutBox,
        ) -> Option<&cv_layout::LayoutBox> {
            if b.max_width.is_some() && matches!(&b.kind, cv_layout::BoxKind::Block { tag } if tag == "div") {
                return Some(b);
            }
            for c in &b.children {
                if let Some(f) = find_div_with_maxwidth(c) {
                    return Some(f);
                }
            }
            None
        }
        let html = r#"<!doctype html><html><head><style>
            .c { max-width: 1400px; margin: 0 auto; }
            .h { width: 100%; }
        </style></head><body><div class="c h">centered</div></body></html>"#;
        let doc = cv_html::parse(html);
        let sheets = collect_stylesheets(&doc);
        let cfg = cv_layout::LayoutConfig {
            viewport_w: 3440.0,
            viewport_h: 800.0,
            measure_text_fn: Some(layout_text_measurer()),
            ..cv_layout::LayoutConfig::default()
        };
        let lb = build_layout_tree(&doc, &sheets, "file:///t", &cfg, &Default::default());
        let div = find_div_with_maxwidth(&lb).expect("container box");
        // Width clamps to 1400; centered → left margin ≈ (3440-1400)/2 = 1020.
        assert!(
            (div.content.w - 1400.0).abs() < 2.0,
            "width clamps to max-width 1400, got {}",
            div.content.w
        );
        assert!(
            (div.content.x - 1020.0).abs() < 4.0,
            "container must CENTER at x≈1020 (margin:0 auto), got x={}",
            div.content.x
        );
    }

    // The hyvechain hero EXACTLY: a flex SECTION whose child is a
    // `max-width:1400 + margin:0 auto + width:100%` container. A flex item's
    // auto main-axis margins must absorb free space and CENTER it (Flexbox
    // §8.1) — this is the "content off to the left on ultrawide" bug.
    #[test]
    fn flex_item_margin_auto_centers_in_wide_viewport() {
        fn find_div_with_maxwidth(
            b: &cv_layout::LayoutBox,
        ) -> Option<&cv_layout::LayoutBox> {
            if b.max_width.is_some()
                && matches!(&b.kind, cv_layout::BoxKind::Block { tag } if tag == "div")
            {
                return Some(b);
            }
            for c in &b.children {
                if let Some(f) = find_div_with_maxwidth(c) {
                    return Some(f);
                }
            }
            None
        }
        let html = r#"<!doctype html><html><head><style>
            .hero { display: flex; align-items: center; }
            .container { max-width: 1400px; margin: 0 auto; }
            .hero-container { width: 100%; }
        </style></head><body>
            <section class="hero"><div class="container hero-container">hero</div></section>
        </body></html>"#;
        let doc = cv_html::parse(html);
        let sheets = collect_stylesheets(&doc);
        let cfg = cv_layout::LayoutConfig {
            viewport_w: 3440.0,
            viewport_h: 800.0,
            measure_text_fn: Some(layout_text_measurer()),
            ..cv_layout::LayoutConfig::default()
        };
        let lb = build_layout_tree(&doc, &sheets, "file:///t", &cfg, &Default::default());
        let div = find_div_with_maxwidth(&lb).expect("hero container box");
        assert!(
            (div.content.w - 1400.0).abs() < 2.0,
            "hero container width clamps to 1400, got {}",
            div.content.w
        );
        assert!(
            (div.content.x - 1020.0).abs() < 6.0,
            "flex item margin:0 auto must CENTER at x≈1020, got x={} (was ~24 = left-packed bug)",
            div.content.x
        );
    }

    #[test]
    fn font_weight_bolder_resolves_against_inherited() {
        fn weight_for_text(b: &cv_layout::LayoutBox, needle: &str) -> Option<u16> {
            if let cv_layout::BoxKind::Text(t) = &b.kind {
                if t.contains(needle) {
                    return Some(b.font_weight_num);
                }
            }
            for c in &b.children {
                if let Some(w) = weight_for_text(c, needle) {
                    return Some(w);
                }
            }
            None
        }
        let html = r#"<!doctype html><html><head><style>
            .p { font-weight: 600; }
            .c { font-weight: bolder; }
        </style></head><body><div class="p">parent<span class="c">child</span></div></body></html>"#;
        let doc = cv_html::parse(html);
        let sheets = collect_stylesheets(&doc);
        let cfg = cv_layout::LayoutConfig {
            viewport_w: 1280.0,
            viewport_h: 800.0,
            measure_text_fn: Some(layout_text_measurer()),
            ..cv_layout::LayoutConfig::default()
        };
        let lb = build_layout_tree(&doc, &sheets, "file:///t", &cfg, &Default::default());
        assert_eq!(weight_for_text(&lb, "parent"), Some(600), "parent stays 600");
        assert_eq!(
            weight_for_text(&lb, "child"),
            Some(900),
            "bolder inside weight-600 must resolve to 900, not a fixed 700"
        );
    }

