    // ---- (c) ★ MIXED-CONTENT block-active / upgrade-passive ----

    #[test]
    fn m91_mixed_content_pure_decision() {
        use cv_net::trust::{MixedContentDecision, ResourceKind, mixed_content_decision};
        assert_eq!(
            mixed_content_decision(true, false, ResourceKind::ActiveScript),
            MixedContentDecision::Block
        );
        assert_eq!(
            mixed_content_decision(true, false, ResourceKind::PassiveImage),
            MixedContentDecision::Upgrade
        );
    }

